static bool vm_net_mock_str_ends_with(const char *text, const char *suffix)
{
    size_t textLen = text ? strlen(text) : 0;
    size_t suffixLen = suffix ? strlen(suffix) : 0;
    if (suffixLen == 0 || textLen < suffixLen)
        return false;
    return strcmp(text + textLen - suffixLen, suffix) == 0;
}

static bool vm_net_mock_scene_name_has_path_separator(const char *scene)
{
    if (scene == NULL)
        return true;
    for (const char *p = scene; *p; ++p)
    {
        if (*p == '/' || *p == '\\' || *p == ':' || (u8)*p < 0x20)
            return true;
    }
    return false;
}

static bool vm_net_mock_scene_name_is_download_key(const char *scene)
{
    /* DSH map names are server-provided resource keys (for example
     * `01桃花岛_01.sce`), not necessarily the older c-prefixed scene form.
     * Reject only empty/path-bearing values; the normal resource-existence
     * check remains the authoritative validation step. */
    return scene != NULL && scene[0] != 0 && !vm_net_mock_scene_name_has_path_separator(scene);
}

static bool vm_net_mock_open_server_scene_resource(const char *scene,
                                                   FILE **fpOut,
                                                   char *pathOut,
                                                   size_t pathOutCap)
{
    static const char *pathFormats[] = {
        "../web/fs/JHOnlineData/%s%s",
        "web/fs/JHOnlineData/%s%s"
    };
    char candidate[1200];

    if (fpOut)
        *fpOut = NULL;
    if (pathOut && pathOutCap != 0)
        pathOut[0] = 0;
    if (scene == NULL || scene[0] == 0 || vm_net_mock_scene_name_has_path_separator(scene))
        return false;

    for (u32 extPass = 0; extPass < 2; ++extPass)
    {
        const char *suffix = extPass == 0 ? "" : ".sce";
        if (extPass != 0 && vm_net_mock_str_ends_with(scene, ".sce"))
            continue;
        if (g_vm_net_mock_resource_dir[0] != 0)
        {
            char resourceName[128];
            FILE *fp = NULL;
            snprintf(resourceName, sizeof(resourceName), "%s%s", scene, suffix);
            if (vm_net_mock_build_configured_resource_path(resourceName, candidate,
                                                           sizeof(candidate)))
            {
                fp = vm_net_mock_fopen_game_path(candidate, "rb");
                if (fp != NULL)
                {
                    if (pathOut && pathOutCap != 0)
                        snprintf(pathOut, pathOutCap, "%s", candidate);
                    if (fpOut)
                        *fpOut = fp;
                    else
                        fclose(fp);
                    return true;
                }
            }
        }
        for (u32 i = 0; i < sizeof(pathFormats) / sizeof(pathFormats[0]); ++i)
        {
            snprintf(candidate, sizeof(candidate), pathFormats[i], scene, suffix);
            FILE *fp = vm_net_mock_fopen_game_path(candidate, "rb");
            if (fp == NULL)
                continue;
            if (pathOut && pathOutCap != 0)
                snprintf(pathOut, pathOutCap, "%s", candidate);
            if (fpOut)
            {
                *fpOut = fp;
            }
            else
            {
                fclose(fp);
            }
            return true;
        }
    }
    return false;
}

static bool vm_net_mock_scene_resource_legacy_alias(const char *scene,
                                                    char *out,
                                                    size_t outCap)
{
    const char *base = scene;
    const char *suffix = NULL;
    const char *end = NULL;
    size_t baseLen = 0;
    size_t stemLen = 0;

    if (out == NULL || outCap == 0)
        return false;
    out[0] = 0;
    if (scene == NULL || scene[0] == 0 ||
        vm_net_mock_scene_name_has_path_separator(scene))
    {
        return false;
    }
    if (base[0] == 'c')
        ++base;
    baseLen = strlen(base);
    end = base + baseLen;
    if (baseLen >= 4 && strcmp(end - 4, ".sce") == 0)
        end -= 4;
    if (end <= base + 5 ||
        base[0] < '0' || base[0] > '9' ||
        base[1] < '0' || base[1] > '9')
    {
        return false;
    }
    suffix = end - 3;
    if (suffix[0] != '_' ||
        suffix[1] < '0' || suffix[1] > '9' ||
        suffix[2] < '0' || suffix[2] > '9' ||
        suffix <= base + 2)
    {
        return false;
    }
    stemLen = (size_t)(suffix - (base + 2));
    if (3u + stemLen + 2u + 4u + 1u > outCap)
        return false;
    out[0] = base[0];
    out[1] = base[1];
    out[2] = '_';
    memcpy(out + 3, base + 2, stemLen);
    out[3 + stemLen] = suffix[1];
    out[4 + stemLen] = suffix[2];
    memcpy(out + 5 + stemLen, ".sce", 5);
    return strcmp(out, scene) != 0;
}

static bool vm_net_mock_open_server_data_resource(const char *name,
                                                  const char *requiredSuffix,
                                                  FILE **fpOut,
                                                  char *pathOut,
                                                  size_t pathOutCap);

static bool vm_net_mock_client_base_data_resource_exists(
    const char *name, const char *requiredSuffix)
{
    static const char *pathFormats[] = {
        /* The service changes cwd to bin/ before startup validation. */
        "JHOnlineData/%s",
        /* Keep validation usable when called from the project root. */
        "bin/JHOnlineData/%s",
        "../bin/JHOnlineData/%s"
    };
    char candidate[1200];

    if (name == NULL || name[0] == 0 ||
        vm_net_mock_scene_name_has_path_separator(name) ||
        (requiredSuffix != NULL && requiredSuffix[0] != 0 &&
         !vm_net_mock_str_ends_with(name, requiredSuffix)))
    {
        return false;
    }
    for (u32 i = 0; i < sizeof(pathFormats) / sizeof(pathFormats[0]); ++i)
    {
        FILE *fp = NULL;
        snprintf(candidate, sizeof(candidate), pathFormats[i], name);
        fp = vm_net_mock_fopen_game_path(candidate, "rb");
        if (fp == NULL)
            continue;
        fclose(fp);
        return true;
    }
    return false;
}

static bool vm_net_mock_client_data_resource_exists(const char *name,
                                                    const char *requiredSuffix)
{
    char candidate[1200];

    if (vm_net_mock_client_base_data_resource_exists(name, requiredSuffix))
        return true;
    if (name == NULL || name[0] == 0 ||
        vm_net_mock_scene_name_has_path_separator(name) ||
        (requiredSuffix != NULL && requiredSuffix[0] != 0 &&
         !vm_net_mock_str_ends_with(name, requiredSuffix)))
    {
        return false;
    }
    if (g_vm_net_mock_resource_dir[0] != 0 &&
        vm_net_mock_build_configured_resource_path(name, candidate,
                                                   sizeof(candidate)))
    {
        FILE *fp = vm_net_mock_fopen_game_path(candidate, "rb");
        if (fp != NULL)
        {
            fclose(fp);
            return true;
        }
    }
    return false;
}

static bool vm_net_mock_scene_resource_exists(const char *scene)
{
    FILE *fp = NULL;
    char legacyScene[64];

    if (!vm_net_mock_open_server_scene_resource(scene, &fp, NULL, 0))
    {
        if (!vm_net_mock_scene_resource_legacy_alias(scene, legacyScene,
                                                     sizeof(legacyScene)) ||
            !vm_net_mock_open_server_scene_resource(legacyScene, &fp, NULL, 0))
        {
            return false;
        }
    }
    fclose(fp);
    return true;
}

static bool vm_net_mock_parse_equipment_enhance_request(
    const u8 *request,
    u32 requestLen,
    vm_net_mock_equipment_enhance_request *parsedOut)
{
    u32 offset = 4;
    u32 seqValue = 0;
    vm_net_mock_request_object object;
    vm_net_mock_equipment_enhance_request parsed;
    const char *seqField = NULL;
    const u8 *rawValue = NULL;
    u16 rawValueLen = 0;

    if (parsedOut)
        memset(parsedOut, 0, sizeof(*parsedOut));
    memset(&parsed, 0, sizeof(parsed));
    if (request == NULL || requestLen < 9 ||
        request[0] != 'W' || request[1] != 'T' ||
        !vm_net_mock_next_request_object(request, requestLen, &offset, &object) ||
        offset != requestLen || object.major != 1 || object.kind != 29 ||
        object.subtype < 1 || object.subtype > 3 || object.payloadLen == 0)
    {
        return false;
    }

    parsed.subtype = object.subtype;
    seqField = parsed.subtype == 1 ? "seq" : "equipseq";
    if (!vm_net_mock_get_object_number_field(object.payload, object.payloadLen,
                                             seqField, &seqValue) ||
        seqValue == 0 || seqValue > 0xffffu)
    {
        return false;
    }
    parsed.equipSeq = (u16)seqValue;
    if (parsed.subtype != 1)
    {
        if (!vm_net_mock_get_object_blob_field(
                object.payload, object.payloadLen, "occultinfo",
                &parsed.occultInfo, &parsed.occultInfoLen))
        {
            if (!vm_net_mock_get_object_entry_bytes(
                    object.payload, object.payloadLen, "occultinfo",
                    &rawValue, &rawValueLen))
            {
                return false;
            }
            if (rawValueLen >= 2 &&
                (u16)((((u16)rawValue[0] << 8) | rawValue[1]) + 2u) ==
                    rawValueLen)
            {
                parsed.occultInfo = rawValue + 2;
                parsed.occultInfoLen = (u16)(rawValueLen - 2);
            }
            else
            {
                parsed.occultInfo = rawValue;
                parsed.occultInfoLen = rawValueLen;
            }
        }
        if (parsed.occultInfoLen == 0 ||
            ((parsed.occultInfoLen % 9 != 0 || parsed.occultInfoLen > 45) &&
             (parsed.occultInfoLen % 5 != 0 || parsed.occultInfoLen > 25)))
        {
            return false;
        }
        parsed.materialRows = (u8)(parsed.occultInfoLen /
                                   (parsed.occultInfoLen % 9 == 0 ? 9 : 5));
    }

    if (parsedOut)
        *parsedOut = parsed;
    return true;
}

static bool vm_net_mock_scene_name_is_safe(const char *scene)
{
    if (scene == NULL || scene[0] == 0)
        return false;
    return vm_net_mock_scene_resource_exists(scene);
}

static bool vm_net_mock_read_runtime_scene_name(char *out, size_t outCap)
{
    u32 sceneObj = 0;

    if (out == NULL || outCap == 0)
        return false;
    out[0] = 0;
    if (Global_R9 == 0)
        return false;
    if (uc_mem_read(MTK, Global_R9 + 0x54AC, &sceneObj, sizeof(sceneObj)) != UC_ERR_OK ||
        sceneObj == 0)
    {
        return false;
    }
    return vm_net_read_guest_raw_cstr(sceneObj + 0x475, out, outCap) &&
           vm_net_mock_scene_name_is_safe(out);
}

static const char *vm_net_mock_normalize_scene_name_for_enter(const char *scene)
{
    static char normalized[64];
    if (!vm_net_mock_scene_name_is_safe(scene))
        return vm_net_mock_default_scene_name();

    /*
     * Fresh actorinfo/sceneKey historically used extensionless c-prefixed town
     * keys (`c00..._01`), which the local file layer resolves to `.sce`.
     * Replaying `c00..._NN.sce` directly can be mistaken for a downloadable
     * resource key on re-enter, so strip only that c-prefixed suffix form.
     */
    if (scene[0] == 'c' && vm_net_mock_str_ends_with(scene, ".sce"))
    {
        size_t len = strlen(scene) - 4;
        if (len >= sizeof(normalized))
            len = sizeof(normalized) - 1;
        memcpy(normalized, scene, len);
        normalized[len] = 0;
        return normalized;
    }
    return scene;
}

static void vm_net_mock_copy_normalized_scene_name(const char *scene, char *out, size_t outCap)
{
    if (out == NULL || outCap == 0)
        return;
    out[0] = 0;
    if (scene == NULL || scene[0] == 0)
        return;
    snprintf(out, outCap, "%s", scene);
    {
        size_t len = strlen(out);
        if (len > 4 && strcmp(out + len - 4, ".sce") == 0)
            out[len - 4] = 0;
    }
}

static bool vm_net_mock_scene_names_equal_loose(const char *a, const char *b)
{
    char normalizedA[64];
    char normalizedB[64];

    vm_net_mock_copy_normalized_scene_name(a, normalizedA, sizeof(normalizedA));
    vm_net_mock_copy_normalized_scene_name(b, normalizedB, sizeof(normalizedB));
    return normalizedA[0] != 0 &&
           normalizedB[0] != 0 &&
           strcmp(normalizedA, normalizedB) == 0;
}

static bool vm_net_mock_add_auto_monster_catalog_item(const u8 *scene,
                                                      u32 sceneLen,
                                                      u32 monster1,
                                                      u32 monster2,
                                                      u32 monster3)
{
    vm_net_mock_auto_monster_catalog_item *item = NULL;
    u32 safeLen = 0;

    if (scene == NULL || sceneLen == 0 ||
        (monster1 == 0 && monster2 == 0 && monster3 == 0) ||
        g_vm_net_mock_auto_monster_catalog_count >= VM_NET_MOCK_AUTO_MONSTER_CATALOG_MAX_ITEMS)
    {
        return false;
    }

    safeLen = vm_net_mock_shop_safe_name_len(scene, sceneLen,
                                             sizeof(g_vm_net_mock_auto_monster_catalog[0].scene) - 1);
    if (safeLen == 0)
        return false;

    item = &g_vm_net_mock_auto_monster_catalog[g_vm_net_mock_auto_monster_catalog_count++];
    memset(item, 0, sizeof(*item));
    memcpy(item->scene, scene, safeLen);
    item->scene[safeLen] = 0;
    item->monsterIds[0] = monster1;
    item->monsterIds[1] = monster2;
    item->monsterIds[2] = monster3;
    return true;
}

static u32 vm_net_mock_load_auto_monster_catalog_dsh(const char *path)
{
    static u8 data[16384];
    u32 len = vm_net_mock_load_response_file(path, data, sizeof(data));
    u32 columnCount = 0;
    u32 rowCount = 0;
    u32 pos = 16;
    u32 added = 0;

    if (len < 16)
        return 0;
    columnCount = vm_net_mock_read_le32_at(data, 4);
    rowCount = vm_net_mock_read_le32_at(data, 8);
    if (columnCount < 4 || columnCount > 16 || rowCount > 512)
        return 0;

    for (u32 i = 0; i < columnCount; ++i)
    {
        u32 fieldLen = 0;
        if (pos >= len)
            return added;
        fieldLen = data[pos++];
        if (pos + fieldLen > len)
            return added;
        pos += fieldLen;
    }

    for (u32 row = 0; row < rowCount && pos + 4 <= len; ++row)
    {
        u32 rowLen = vm_net_mock_read_le32_at(data, pos);
        u32 rowPos = pos + 4;
        u32 rowEnd = rowPos + rowLen;
        const u8 *scene = NULL;
        u32 sceneLen = 0;
        u32 monsterIds[3] = {0, 0, 0};

        if (rowEnd > len || rowEnd < rowPos)
            break;

        for (u32 col = 0; col < columnCount && rowPos < rowEnd; ++col)
        {
            u32 valueLen = data[rowPos++];
            const u8 *value = data + rowPos;

            if (rowPos + valueLen > rowEnd)
                break;
            if (col == 0)
            {
                scene = value;
                sceneLen = valueLen;
            }
            else if (col >= 1 && col <= 3)
            {
                monsterIds[col - 1] = vm_net_mock_parse_dsh_u32(value, valueLen, 0);
            }
            rowPos += valueLen;
        }

        if (vm_net_mock_add_auto_monster_catalog_item(scene, sceneLen,
                                                      monsterIds[0],
                                                      monsterIds[1],
                                                      monsterIds[2]))
        {
            ++added;
        }
        pos = rowEnd;
    }

    return added;
}

static u32 vm_net_mock_load_auto_monster_catalog(void)
{
    u32 added = 0;

    if (g_vm_net_mock_auto_monster_catalog_loaded)
        return g_vm_net_mock_auto_monster_catalog_count;

    g_vm_net_mock_auto_monster_catalog_loaded = true;
    g_vm_net_mock_auto_monster_catalog_count = 0;
    added = vm_net_mock_load_auto_monster_catalog_dsh("JHOnlineData/automonster.dsh");
    if (added == 0)
        added = vm_net_mock_load_auto_monster_catalog_dsh("bin/JHOnlineData/automonster.dsh");
    if (added == 0)
        added = vm_net_mock_load_auto_monster_catalog_dsh("web/fs/JHOnlineData/automonster.dsh");

    if (added == 0)
    {
        printf("[warn][network] mock_auto_monster_catalog missing source=automonster.dsh\n");
    }
    else
    {
        printf("[info][network] mock_auto_monster_catalog total=%u source=automonster.dsh\n",
               g_vm_net_mock_auto_monster_catalog_count);
    }
    return g_vm_net_mock_auto_monster_catalog_count;
}

static bool vm_net_mock_select_auto_monster_for_scene(const char *scene,
                                                      u32 *enemyIdOut,
                                                      const char **matchedSceneOut)
{
    u32 total = vm_net_mock_load_auto_monster_catalog();
    u32 overrideEnemyId = vm_net_mock_env_u32("CBE_HANGUP_BATTLE_ENEMY_ID", 0);

    if (enemyIdOut)
        *enemyIdOut = 0;
    if (matchedSceneOut)
        *matchedSceneOut = NULL;
    if (overrideEnemyId != 0)
    {
        if (enemyIdOut)
            *enemyIdOut = overrideEnemyId;
        if (matchedSceneOut)
            *matchedSceneOut = "env:CBE_HANGUP_BATTLE_ENEMY_ID";
        return true;
    }
    if (scene == NULL || scene[0] == 0)
        return false;

    for (u32 i = 0; i < total; ++i)
    {
        const vm_net_mock_auto_monster_catalog_item *item = &g_vm_net_mock_auto_monster_catalog[i];
        u32 choices[3] = {0, 0, 0};
        u32 choiceCount = 0;

        if (!vm_net_mock_scene_names_equal_loose(scene, item->scene))
            continue;
        for (u32 j = 0; j < 3; ++j)
        {
            if (item->monsterIds[j] != 0)
                choices[choiceCount++] = item->monsterIds[j];
        }
        if (choiceCount == 0)
            return false;
        if (enemyIdOut)
            *enemyIdOut = choices[g_schedulerTick % choiceCount];
        if (matchedSceneOut)
            *matchedSceneOut = item->scene;
        return true;
    }

    return false;
}

static bool vm_net_mock_scene_is_c00_penglai03(const char *scene)
{
    return scene != NULL &&
           (strcmp(scene, "\x63\x30\x30\xc5\xee\xc0\xb3\xcf\xc9\xb5\xba\x5f\x30\x33") == 0 ||
            strcmp(scene, "\x63\x30\x30\xc5\xee\xc0\xb3\xcf\xc9\xb5\xba\x5f\x30\x33\x2e\x73\x63\x65") == 0);
}

static bool vm_net_mock_scene_is_taohuadao01(const char *scene)
{
    return scene != NULL &&
           strcmp(scene, "\x30\x31\xcc\xd2\xbb\xa8\xb5\xba\x5f\x30\x31\x2e\x73\x63\x65") == 0;
}

static bool vm_net_mock_adjust_safe_player_pos_from_sce(const char *scene, u16 *x, u16 *y);
static bool vm_net_mock_get_scene_reasonable_spawn_from_sce(const char *scene,
                                                            u16 *xOut,
                                                            u16 *yOut,
                                                            u16 *entryIdOut);

static void vm_net_mock_adjust_safe_player_pos_for_scene(const char *scene, u16 *x, u16 *y)
{
    if (scene == NULL || x == NULL || y == NULL)
        return;

    /*
     * SCE edge_portal spawn_point marks the portal glyph/trigger approach, not
     * a good player restore point. Restoring exactly on those coordinates makes
     * the yellow portal marker appear under the player or under the bottom UI.
     */
    if (vm_net_mock_scene_is_penglai04(scene) &&
        *x >= 224 && *x <= 288 &&
        *y >= 256 && *y <= 304)
    {
        *x = 256;
        *y = 245;
        return;
    }

    if (vm_net_mock_scene_is_penglai03(scene) &&
        *x >= 64 && *x <= 144 &&
        *y >= 390)
    {
        *x = 105;
        *y = 360;
        return;
    }

    (void)vm_net_mock_adjust_safe_player_pos_from_sce(scene, x, y);
}

static void vm_net_mock_role_db_path(char *path, size_t pathSize)
{
    char safeAccount[64];
    const char *accountId = g_vm_mock_service_active_account_id;
    size_t outPos = 0;

    if (path == NULL || pathSize == 0)
        return;
    path[0] = 0;
    if (accountId == NULL || accountId[0] == 0)
        return;

    memset(safeAccount, 0, sizeof(safeAccount));
    for (size_t i = 0; accountId[i] != 0 && outPos + 1 < sizeof(safeAccount); ++i)
    {
        unsigned char ch = (unsigned char)accountId[i];
        if ((ch >= '0' && ch <= '9') ||
            (ch >= 'A' && ch <= 'Z') ||
            (ch >= 'a' && ch <= 'z') ||
            ch == '_' || ch == '-')
        {
            safeAccount[outPos++] = (char)ch;
        }
        else
        {
            safeAccount[outPos++] = '_';
        }
    }
    if (outPos == 0)
        return;
    snprintf(path, pathSize, "nvram/accounts/%s/jhol_mock_roles.bin", safeAccount);
}

static void vm_mock_service_account_db_path(char *path, size_t pathSize)
{
    if (path == NULL || pathSize == 0)
        return;
    snprintf(path, pathSize, "nvram/mock_service_accounts.bin");
}

static size_t vm_mock_mysql_bounded_strlen(const char *text, size_t capacity)
{
    size_t length = 0;
    if (text == NULL)
        return 0;
    while (length < capacity && text[length] != 0)
        ++length;
    return length;
}

static bool vm_mock_mysql_copy_text(char *destination,
                                    size_t destination_size,
                                    const char *value,
                                    size_t value_len)
{
    if (destination == NULL || destination_size == 0 || value == NULL || value_len >= destination_size)
        return false;
    memcpy(destination, value, value_len);
    destination[value_len] = 0;
    return true;
}

static bool vm_mock_mysql_parse_u32(const char *value, size_t value_len, u32 *result_out)
{
    uint64_t result = 0;
    if (value == NULL || value_len == 0 || result_out == NULL)
        return false;
    for (size_t i = 0; i < value_len; ++i)
    {
        if (value[i] < '0' || value[i] > '9')
            return false;
        result = result * 10u + (u32)(value[i] - '0');
        if (result > 0xffffffffu)
            return false;
    }
    *result_out = (u32)result;
    return true;
}

typedef struct
{
    vm_mock_service_account_db_file *database;
    bool invalid;
} vm_mock_mysql_account_load_context;

static bool vm_mock_mysql_account_row(void *context_value,
                                      unsigned int column_count,
                                      const char *const *values,
                                      const size_t *lengths)
{
    vm_mock_mysql_account_load_context *context = (vm_mock_mysql_account_load_context *)context_value;
    if (context == NULL || context->database == NULL || column_count != 2 ||
        context->database->accountCount >= VM_MOCK_SERVICE_ACCOUNT_DB_MAX_ACCOUNTS)
    {
        if (context != NULL)
            context->invalid = true;
        return true;
    }
    vm_mock_service_account_record *record =
        &context->database->accounts[context->database->accountCount];
    size_t password_len = 0;
    memset(record, 0, sizeof(*record));
    if (!vm_mock_mysql_copy_text(record->username, sizeof(record->username), values[0], lengths[0]) ||
        values[1] == NULL ||
        !vm_mysql_hex_decode(values[1], lengths[1], record->password,
                             sizeof(record->password) - 1, &password_len))
    {
        context->invalid = true;
        memset(record, 0, sizeof(*record));
        return true;
    }
    record->password[password_len] = 0;
    ++context->database->accountCount;
    return true;
}

static bool vm_mock_service_account_db_load_legacy(void)
{
    char path[128];
    vm_mock_service_account_db_file loaded;
    vm_mock_service_account_db_path(path, sizeof(path));
    FILE *fp = fopen(path, "rb");
    if (fp == NULL)
        return false;
    memset(&loaded, 0, sizeof(loaded));
    bool valid = fread(&loaded, 1, sizeof(loaded), fp) == sizeof(loaded) &&
                 memcmp(loaded.magic, "JHA1", 4) == 0 &&
                 loaded.version == VM_MOCK_SERVICE_ACCOUNT_DB_VERSION &&
                 loaded.accountCount <= VM_MOCK_SERVICE_ACCOUNT_DB_MAX_ACCOUNTS;
    fclose(fp);
    if (!valid)
        return false;
    g_vm_mock_service_account_db = loaded;
    return true;
}

static void vm_mock_service_account_db_save(const char *reason)
{
    if (!g_vm_mock_service_account_db_valid)
        return;
    memcpy(g_vm_mock_service_account_db.magic, "JHA1", 4);
    g_vm_mock_service_account_db.version = VM_MOCK_SERVICE_ACCOUNT_DB_VERSION;
    if (g_vm_mock_service_account_db.accountCount > VM_MOCK_SERVICE_ACCOUNT_DB_MAX_ACCOUNTS)
        g_vm_mock_service_account_db.accountCount = VM_MOCK_SERVICE_ACCOUNT_DB_MAX_ACCOUNTS;

    if (!vm_mysql_exec("START TRANSACTION") || !vm_mysql_exec("DELETE FROM accounts"))
    {
        char mysql_error[512];
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        vm_mysql_exec("ROLLBACK");
        vm_autotest_note("mock_account_db_mysql_save_failed reason=%s error=%s\n",
                         reason ? reason : "state", mysql_error);
        return;
    }
    for (u32 i = 0; i < g_vm_mock_service_account_db.accountCount; ++i)
    {
        const vm_mock_service_account_record *record = &g_vm_mock_service_account_db.accounts[i];
        char username_hex[sizeof(record->username) * 2 + 1];
        char password_hex[sizeof(record->password) * 2 + 1];
        char query[768];
        size_t username_len = vm_mock_mysql_bounded_strlen(record->username, sizeof(record->username));
        size_t password_len = vm_mock_mysql_bounded_strlen(record->password, sizeof(record->password));
        if (username_len == 0 || username_len >= sizeof(record->username) ||
            password_len >= sizeof(record->password) ||
            vm_mysql_hex_encode(record->username, username_len, username_hex, sizeof(username_hex)) == 0 ||
            vm_mysql_hex_encode(record->password, password_len, password_hex, sizeof(password_hex)) == 0)
        {
            vm_mysql_exec("ROLLBACK");
            vm_autotest_note("mock_account_db_mysql_save_failed reason=%s error=invalid-account-record index=%u\n",
                             reason ? reason : "state", i);
            return;
        }
        snprintf(query, sizeof(query),
                 "INSERT INTO accounts(account_id,password_value) VALUES(CAST(X'%s' AS CHAR),X'%s')",
                 username_hex, password_hex);
        if (!vm_mysql_exec(query))
        {
            vm_autotest_note("mock_account_db_mysql_save_failed reason=%s index=%u error=%s\n",
                             reason ? reason : "state", i, vm_mysql_last_error());
            vm_mysql_exec("ROLLBACK");
            return;
        }
    }
    if (!vm_mysql_exec("COMMIT"))
    {
        vm_autotest_note("mock_account_db_mysql_save_failed reason=%s error=%s\n",
                         reason ? reason : "state", vm_mysql_last_error());
        return;
    }
    vm_autotest_note("mock_account_db_mysql_save reason=%s count=%u\n",
                     reason ? reason : "state",
                     g_vm_mock_service_account_db.accountCount);
}

static void vm_mock_service_account_db_load(void)
{
    if (g_vm_mock_service_account_db_loaded)
        return;
    g_vm_mock_service_account_db_loaded = true;
    memset(&g_vm_mock_service_account_db, 0, sizeof(g_vm_mock_service_account_db));
    memcpy(g_vm_mock_service_account_db.magic, "JHA1", 4);
    g_vm_mock_service_account_db.version = VM_MOCK_SERVICE_ACCOUNT_DB_VERSION;
    g_vm_mock_service_account_db_valid = true;

    vm_mock_mysql_account_load_context context;
    memset(&context, 0, sizeof(context));
    context.database = &g_vm_mock_service_account_db;
    if (!vm_mysql_query("SELECT account_id,HEX(password_value) FROM accounts ORDER BY account_id",
                        vm_mock_mysql_account_row, &context))
    {
        g_vm_mock_service_account_db_valid = false;
        vm_autotest_note("mock_account_db_mysql_load_failed error=%s\n", vm_mysql_last_error());
        return;
    }
    if (context.invalid)
    {
        memset(&g_vm_mock_service_account_db, 0, sizeof(g_vm_mock_service_account_db));
        g_vm_mock_service_account_db_valid = false;
        vm_autotest_note("mock_account_db_mysql_load_failed error=invalid-row\n");
        return;
    }
    if (g_vm_mock_service_account_db.accountCount == 0 && vm_mock_service_account_db_load_legacy())
    {
        vm_autotest_note("mock_account_db_legacy_migrate count=%u\n",
                         g_vm_mock_service_account_db.accountCount);
        vm_mock_service_account_db_save("legacy-migrate");
    }
    vm_autotest_note("mock_account_db_mysql_load count=%u\n",
                     g_vm_mock_service_account_db.accountCount);
}

