static void vm_net_mock_apply_role_id_migration_to_friend_cache(const char *account_id,
                                                                 const u32 *old_ids,
                                                                 const u32 *new_ids,
                                                                 u32 mapping_count)
{
    if (account_id == NULL || old_ids == NULL || new_ids == NULL)
        return;
    for (u32 i = 0; i < g_vm_mock_service_friend_db.recordCount; ++i)
    {
        vm_mock_service_friend_record *record = &g_vm_mock_service_friend_db.records[i];
        for (u32 j = 0; j < mapping_count; ++j)
        {
            if (strcmp(record->ownerAccountId, account_id) == 0 && record->ownerRoleId == old_ids[j])
                record->ownerRoleId = new_ids[j];
            if (strcmp(record->targetAccountId, account_id) == 0 && record->targetRoleId == old_ids[j])
                record->targetRoleId = new_ids[j];
        }
    }
}

static bool vm_net_mock_role_db_save_relational(const char *reason,
                                                 const u32 *old_ids,
                                                 const u32 *new_ids,
                                                 u32 mapping_count)
{
    const char *account_id = g_vm_mock_service_active_account_id;
    char account_hex[129];
    char query[3072];
    char mysql_error[512];
    char *bulk_query = NULL;
    size_t bulk_capacity = 131072;
    bool transaction_started = false;
    mysql_error[0] = 0;

    if (!g_vm_net_mock_role_db_valid || !vm_net_mock_mysql_account_hex(account_hex))
        return false;
    memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
    g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
    if (g_vm_net_mock_role_db.roleCount > VM_NET_MOCK_ROLE_DB_MAX_ROLES)
        g_vm_net_mock_role_db.roleCount = VM_NET_MOCK_ROLE_DB_MAX_ROLES;
    if (g_vm_net_mock_role_db.roleCount == 0)
        g_vm_net_mock_role_db.activeRoleId = 0;

    bulk_query = (char *)malloc(bulk_capacity);
    if (bulk_query == NULL)
        return false;
    if (!vm_mysql_exec("START TRANSACTION"))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }
    transaction_started = true;
    snprintf(query, sizeof(query),
             "INSERT INTO account_role_state(account_id,format_version,active_role_id,role_count) "
             "VALUES(CAST(X'%s' AS CHAR),%u,%u,%u) ON DUPLICATE KEY UPDATE "
             "format_version=VALUES(format_version),active_role_id=VALUES(active_role_id),role_count=VALUES(role_count)",
             account_hex, VM_NET_MOCK_ROLE_DB_VERSION,
             g_vm_net_mock_role_db.activeRoleId, g_vm_net_mock_role_db.roleCount);
    if (!vm_mysql_exec(query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }
    /* Keep existing role rows alive while saving normal role state.  Guilds,
     * guild_members and guild_applications intentionally reference these rows
     * with ON DELETE CASCADE, so the former delete-and-reinsert save erased a
     * role's guild every time role-select/position/battle state was persisted.
     * Delete only roles that really disappeared from the account, move the
     * surviving role_index values out of the live range to avoid unique-index
     * collisions, then upsert them in their current order. */
    if (g_vm_net_mock_role_db.roleCount == 0)
    {
        snprintf(query, sizeof(query),
                 "DELETE FROM account_roles WHERE account_id=CAST(X'%s' AS CHAR)",
                 account_hex);
    }
    else
    {
        size_t query_len = (size_t)snprintf(
            query, sizeof(query),
            "DELETE FROM account_roles WHERE account_id=CAST(X'%s' AS CHAR) AND role_id NOT IN (",
            account_hex);
        for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
        {
            int written = snprintf(query + query_len, sizeof(query) - query_len,
                                   "%s%u", i ? "," : "",
                                   g_vm_net_mock_role_db.roles[i].roleId);
            if (written < 0 || (size_t)written >= sizeof(query) - query_len)
            {
                snprintf(mysql_error, sizeof(mysql_error), "role-id delete query too large");
                goto failed;
            }
            query_len += (size_t)written;
        }
        if (query_len + 2 > sizeof(query))
        {
            snprintf(mysql_error, sizeof(mysql_error), "role-id delete query too large");
            goto failed;
        }
        query[query_len++] = ')';
        query[query_len] = 0;
    }
    if (!vm_mysql_exec(query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }
    if (g_vm_net_mock_role_db.roleCount != 0)
    {
        snprintf(query, sizeof(query),
                 "UPDATE account_roles SET role_index=role_index+128 "
                 "WHERE account_id=CAST(X'%s' AS CHAR)", account_hex);
        if (!vm_mysql_exec(query))
        {
            snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
            goto failed;
        }
    }
    snprintf(query, sizeof(query),
             "DELETE FROM account_role_equipment WHERE account_id=CAST(X'%s' AS CHAR)",
             account_hex);
    if (!vm_mysql_exec(query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }
    snprintf(query, sizeof(query),
             "DELETE FROM account_role_backpack WHERE account_id=CAST(X'%s' AS CHAR)",
             account_hex);
    if (!vm_mysql_exec(query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }

    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        const vm_net_mock_role_state *role = &g_vm_net_mock_role_db.roles[i];
        char name_hex[sizeof(role->name) * 2 + 1];
        char scene_hex[sizeof(role->scene) * 2 + 1];
        size_t name_len = vm_mock_mysql_bounded_strlen(role->name, sizeof(role->name));
        size_t scene_len = vm_mock_mysql_bounded_strlen(role->scene, sizeof(role->scene));
        if (name_len >= sizeof(role->name) || scene_len >= sizeof(role->scene) ||
            (name_len && vm_mysql_hex_encode(role->name, name_len, name_hex, sizeof(name_hex)) == 0) ||
            (scene_len && vm_mysql_hex_encode(role->scene, scene_len, scene_hex, sizeof(scene_hex)) == 0))
        {
            snprintf(mysql_error, sizeof(mysql_error), "invalid role text at index %u", i);
            goto failed;
        }
        if (!name_len)
            name_hex[0] = 0;
        if (!scene_len)
            scene_hex[0] = 0;
        snprintf(query, sizeof(query),
                 "INSERT INTO account_roles(account_id,role_id,role_index,role_name,job,sex,backpack_capacity,level,exp,hp,hp_max,mp,mp_max,money,wcoin,scene,pos_x,pos_y,backpack_item_count,designation_id,next_backpack_seq) "
                 "VALUES(CAST(X'%s' AS CHAR),%u,%u,X'%s',%u,%u,%u,%u,%u,%u,%u,%u,%u,%u,%u,X'%s',%u,%u,%u,%u,%u) "
                 "ON DUPLICATE KEY UPDATE role_index=VALUES(role_index),role_name=VALUES(role_name),"
                 "job=VALUES(job),sex=VALUES(sex),backpack_capacity=VALUES(backpack_capacity),"
                 "level=VALUES(level),exp=VALUES(exp),hp=VALUES(hp),hp_max=VALUES(hp_max),"
                 "mp=VALUES(mp),mp_max=VALUES(mp_max),money=VALUES(money),wcoin=VALUES(wcoin),"
                 "scene=VALUES(scene),pos_x=VALUES(pos_x),pos_y=VALUES(pos_y),"
                 "backpack_item_count=VALUES(backpack_item_count),designation_id=VALUES(designation_id),"
                 "next_backpack_seq=VALUES(next_backpack_seq)",
                 account_hex, role->roleId, i, name_hex, role->job, role->sex,
                 role->backpackCapacity, role->level, role->exp, role->hp, role->hpMax,
                 role->mp, role->mpMax, role->money, role->wcoin, scene_hex,
                 role->x, role->y, role->backpackItemCount, role->designationId,
                 role->nextBackpackSeq);
        if (!vm_mysql_exec(query))
        {
            snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
            goto failed;
        }
    }

    size_t bulk_len = (size_t)snprintf(
        bulk_query, bulk_capacity,
        "INSERT INTO account_role_equipment(account_id,role_id,slot_index,item_id) VALUES");
    u32 bulk_rows = 0;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        const vm_net_mock_role_state *role = &g_vm_net_mock_role_db.roles[i];
        for (u32 slot = 0; slot < VM_NET_MOCK_EQUIP_SLOT_COUNT; ++slot)
        {
            if (role->equippedItemIds[slot] == 0)
                continue;
            int written = snprintf(bulk_query + bulk_len, bulk_capacity - bulk_len,
                                   "%s(CAST(X'%s' AS CHAR),%u,%u,%u)",
                                   bulk_rows ? "," : "", account_hex, role->roleId,
                                   slot, role->equippedItemIds[slot]);
            if (written < 0 || (size_t)written >= bulk_capacity - bulk_len)
            {
                snprintf(mysql_error, sizeof(mysql_error), "equipment query too large");
                goto failed;
            }
            bulk_len += (size_t)written;
            ++bulk_rows;
        }
    }
    if (bulk_rows && !vm_mysql_exec(bulk_query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }

    bulk_len = (size_t)snprintf(
        bulk_query, bulk_capacity,
        "INSERT INTO account_role_backpack(account_id,role_id,slot_index,item_id,item_seq,item_count,enhance_level) VALUES");
    bulk_rows = 0;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        const vm_net_mock_role_state *role = &g_vm_net_mock_role_db.roles[i];
        for (u32 slot = 0; slot < VM_NET_MOCK_BACKPACK_MAX_ITEMS; ++slot)
        {
            const vm_net_mock_backpack_item_state *item = &role->backpackItems[slot];
            if (item->itemId == 0 && item->seq == 0 && item->count == 0)
                continue;
            int written = snprintf(bulk_query + bulk_len, bulk_capacity - bulk_len,
                                   "%s(CAST(X'%s' AS CHAR),%u,%u,%u,%u,%u,%u)",
                                   bulk_rows ? "," : "", account_hex, role->roleId,
                                   slot, item->itemId, item->seq, item->count,
                                   item->enhanceLevel);
            if (written < 0 || (size_t)written >= bulk_capacity - bulk_len)
            {
                snprintf(mysql_error, sizeof(mysql_error), "backpack query too large");
                goto failed;
            }
            bulk_len += (size_t)written;
            ++bulk_rows;
        }
    }
    if (bulk_rows && !vm_mysql_exec(bulk_query))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }

    for (u32 i = 0; i < mapping_count; ++i)
    {
        if (old_ids == NULL || new_ids == NULL || old_ids[i] == new_ids[i])
            continue;
        snprintf(query, sizeof(query),
                 "UPDATE friendships SET owner_role_id=%u WHERE owner_account_id=CAST(X'%s' AS CHAR) AND owner_role_id=%u",
                 new_ids[i], account_hex, old_ids[i]);
        if (!vm_mysql_exec(query))
        {
            snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
            goto failed;
        }
        snprintf(query, sizeof(query),
                 "UPDATE friendships SET target_role_id=%u WHERE target_account_id=CAST(X'%s' AS CHAR) AND target_role_id=%u",
                 new_ids[i], account_hex, old_ids[i]);
        if (!vm_mysql_exec(query))
        {
            snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
            goto failed;
        }
    }
    if (!vm_mysql_exec("COMMIT"))
    {
        snprintf(mysql_error, sizeof(mysql_error), "%s", vm_mysql_last_error());
        goto failed;
    }
    free(bulk_query);
    g_vm_net_mock_role_position_dirty = false;
    vm_autotest_note("mock_role_db_mysql_save account=%s reason=%s roles=%u active=%u storage=relational\n",
                     account_id ? account_id : "-", reason ? reason : "state",
                     g_vm_net_mock_role_db.roleCount, g_vm_net_mock_role_db.activeRoleId);
    return true;

failed:
    if (transaction_started)
        vm_mysql_exec("ROLLBACK");
    vm_autotest_note("mock_role_db_mysql_save_failed account=%s reason=%s error=%s\n",
                     account_id ? account_id : "-", reason ? reason : "state",
                     mysql_error[0] ? mysql_error : "unknown");
    free(bulk_query);
    return false;
}

static void vm_net_mock_role_db_save(const char *reason)
{
    (void)vm_net_mock_role_db_save_relational(reason, NULL, NULL, 0);
}

static void vm_net_mock_role_db_load(void)
{
    char path[128];
    u8 fileBuf[sizeof(vm_net_mock_role_db_file)];
    vm_net_mock_role_db_file loaded;
    vm_net_mock_role_db_file_v4 shopWcoinFile;
    vm_net_mock_role_db_file_v3 equippedBackpackFile;
    vm_net_mock_role_db_file_v2 backpackFile;
    vm_net_mock_role_db_file_v1 legacy;
    bool loadedFromFile = false;
    bool loadedFromMysql = false;
    bool loadedFromPayload = false;
    bool needsSave = false;
    u32 migratedOldIds[VM_NET_MOCK_ROLE_DB_MAX_ROLES];
    u32 migratedNewIds[VM_NET_MOCK_ROLE_DB_MAX_ROLES];
    u32 migratedIdCount = 0;

    if (g_vm_net_mock_role_db_loaded)
        return;
    g_vm_net_mock_role_db_loaded = true;
    memset(&g_vm_net_mock_role_db, 0, sizeof(g_vm_net_mock_role_db));
    memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
    g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
    g_vm_net_mock_role_db.activeRoleId = 0;
    g_vm_net_mock_role_db.roleCount = 0;

    memset(migratedOldIds, 0, sizeof(migratedOldIds));
    memset(migratedNewIds, 0, sizeof(migratedNewIds));
    if (!vm_net_mock_role_db_load_mysql_relational(&loadedFromMysql))
    {
        vm_autotest_note("mock_role_db_mysql_load_failed account=%s storage=relational error=%s\n",
                         g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                         vm_mysql_last_error());
        g_vm_net_mock_role_db_valid = false;
        return;
    }
    if (!loadedFromMysql &&
        !vm_net_mock_role_db_load_mysql_payload_backup(&loadedFromPayload))
    {
        vm_autotest_note("mock_role_db_mysql_load_failed account=%s storage=payload-backup error=%s\n",
                         g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                         vm_mysql_last_error());
        g_vm_net_mock_role_db_valid = false;
        return;
    }

    vm_net_mock_role_db_path(path, sizeof(path));
    if (path[0] == 0)
    {
        g_vm_net_mock_role_db_valid = false;
        return;
    }
    FILE *fp = (loadedFromMysql || loadedFromPayload) ? NULL : fopen(path, "rb");
    if (fp)
    {
        size_t readLen = fread(fileBuf, 1, sizeof(fileBuf), fp);
        fclose(fp);
        if (readLen == sizeof(loaded))
            memcpy(&loaded, fileBuf, sizeof(loaded));
        if (readLen == sizeof(loaded) &&
            memcmp(loaded.magic, "JHR1", 4) == 0 &&
            loaded.version == VM_NET_MOCK_ROLE_DB_VERSION &&
            loaded.roleCount <= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
        {
            g_vm_net_mock_role_db = loaded;
            loadedFromFile = true;
        }
        else if (readLen == sizeof(equippedBackpackFile))
        {
            memcpy(&equippedBackpackFile, fileBuf, sizeof(equippedBackpackFile));
            if (memcmp(equippedBackpackFile.magic, "JHR1", 4) == 0 &&
                equippedBackpackFile.version == VM_NET_MOCK_ROLE_DB_EQUIP_VERSION &&
                equippedBackpackFile.roleCount <= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
            {
                memset(&g_vm_net_mock_role_db, 0, sizeof(g_vm_net_mock_role_db));
                memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
                g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
                g_vm_net_mock_role_db.activeRoleId = equippedBackpackFile.activeRoleId;
                g_vm_net_mock_role_db.roleCount = equippedBackpackFile.roleCount;
                for (u32 i = 0; i < equippedBackpackFile.roleCount; ++i)
                    vm_net_mock_role_copy_from_v3(&g_vm_net_mock_role_db.roles[i],
                                                  &equippedBackpackFile.roles[i]);
                loadedFromFile = true;
                needsSave = true;
                vm_autotest_note("mock_role_db_migrate version=3->5 roles=%u active=%u\n",
                                 g_vm_net_mock_role_db.roleCount,
                                 g_vm_net_mock_role_db.activeRoleId);
            }
        }
        else if (readLen == sizeof(shopWcoinFile))
        {
            memcpy(&shopWcoinFile, fileBuf, sizeof(shopWcoinFile));
            if (memcmp(shopWcoinFile.magic, "JHR1", 4) == 0 &&
                shopWcoinFile.version == VM_NET_MOCK_ROLE_DB_SHOP_WCOIN_VERSION &&
                shopWcoinFile.roleCount <= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
            {
                memset(&g_vm_net_mock_role_db, 0, sizeof(g_vm_net_mock_role_db));
                memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
                g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
                g_vm_net_mock_role_db.activeRoleId = shopWcoinFile.activeRoleId;
                g_vm_net_mock_role_db.roleCount = shopWcoinFile.roleCount;
                for (u32 i = 0; i < shopWcoinFile.roleCount; ++i)
                    vm_net_mock_role_copy_from_v4(&g_vm_net_mock_role_db.roles[i],
                                                  &shopWcoinFile.roles[i]);
                loadedFromFile = true;
                needsSave = true;
                vm_autotest_note("mock_role_db_migrate version=4->5 roles=%u active=%u\n",
                                 g_vm_net_mock_role_db.roleCount,
                                 g_vm_net_mock_role_db.activeRoleId);
            }
        }
        else if (readLen == sizeof(backpackFile))
        {
            memcpy(&backpackFile, fileBuf, sizeof(backpackFile));
            if (memcmp(backpackFile.magic, "JHR1", 4) == 0 &&
                backpackFile.version == VM_NET_MOCK_ROLE_DB_BACKPACK_VERSION &&
                backpackFile.roleCount <= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
            {
                memset(&g_vm_net_mock_role_db, 0, sizeof(g_vm_net_mock_role_db));
                memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
                g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
                g_vm_net_mock_role_db.activeRoleId = backpackFile.activeRoleId;
                g_vm_net_mock_role_db.roleCount = backpackFile.roleCount;
                for (u32 i = 0; i < backpackFile.roleCount; ++i)
                    vm_net_mock_role_copy_from_v2(&g_vm_net_mock_role_db.roles[i],
                                                  &backpackFile.roles[i]);
                loadedFromFile = true;
                needsSave = true;
                vm_autotest_note("mock_role_db_migrate version=2->5 roles=%u active=%u\n",
                                 g_vm_net_mock_role_db.roleCount,
                                 g_vm_net_mock_role_db.activeRoleId);
            }
        }
        else if (readLen == sizeof(legacy))
        {
            memcpy(&legacy, fileBuf, sizeof(legacy));
            if (memcmp(legacy.magic, "JHR1", 4) == 0 &&
                legacy.version == VM_NET_MOCK_ROLE_DB_LEGACY_VERSION &&
                legacy.roleCount <= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
            {
                memset(&g_vm_net_mock_role_db, 0, sizeof(g_vm_net_mock_role_db));
                memcpy(g_vm_net_mock_role_db.magic, "JHR1", 4);
                g_vm_net_mock_role_db.version = VM_NET_MOCK_ROLE_DB_VERSION;
                g_vm_net_mock_role_db.activeRoleId = legacy.activeRoleId;
                g_vm_net_mock_role_db.roleCount = legacy.roleCount;
                for (u32 i = 0; i < legacy.roleCount; ++i)
                    vm_net_mock_role_copy_from_v1(&g_vm_net_mock_role_db.roles[i],
                                                  &legacy.roles[i]);
                loadedFromFile = true;
                needsSave = true;
                vm_autotest_note("mock_role_db_migrate version=1->5 roles=%u active=%u\n",
                                 g_vm_net_mock_role_db.roleCount,
                                 g_vm_net_mock_role_db.activeRoleId);
            }
        }
    }

    if (loadedFromFile)
    {
        /* The old file is read only as a one-time import source. */
        needsSave = true;
    }
    else if (loadedFromPayload)
    {
        needsSave = true;
    }
    else if (!loadedFromMysql)
    {
        needsSave = true;
    }

    if (g_vm_net_mock_role_db.roleCount > VM_NET_MOCK_ROLE_DB_MAX_ROLES)
    {
        memset(g_vm_net_mock_role_db.roles, 0, sizeof(g_vm_net_mock_role_db.roles));
        g_vm_net_mock_role_db.roleCount = 0;
        g_vm_net_mock_role_db.activeRoleId = 0;
        needsSave = true;
    }
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (vm_net_mock_role_canonicalize_initial_scene(&g_vm_net_mock_role_db.roles[i]))
        {
            needsSave = true;
            vm_autotest_note("mock_role_initial_scene_migrate account=%s role=%u scene=c00-penglai-01.sce\n",
                             g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                             g_vm_net_mock_role_db.roles[i].roleId);
        }
        vm_net_mock_role_normalize(&g_vm_net_mock_role_db.roles[i]);
    }
    if (g_vm_net_mock_role_db.roleCount == 1 &&
        vm_net_mock_role_is_pristine_bootstrap_default(&g_vm_net_mock_role_db.roles[0]))
    {
        memset(g_vm_net_mock_role_db.roles, 0, sizeof(g_vm_net_mock_role_db.roles));
        g_vm_net_mock_role_db.roleCount = 0;
        g_vm_net_mock_role_db.activeRoleId = 0;
        needsSave = true;
        vm_autotest_note("mock_role_db_drop_bootstrap_default active=%u\n",
                         g_vm_net_mock_role_db.activeRoleId);
    }
    u32 repairedDefaultNames = vm_net_mock_role_db_repair_duplicate_default_names();
    if (repairedDefaultNames > 0)
    {
        needsSave = true;
        vm_autotest_note("mock_role_db_repair_duplicate_default_names count=%u roles=%u active=%u\n",
                         repairedDefaultNames,
                         g_vm_net_mock_role_db.roleCount,
                         g_vm_net_mock_role_db.activeRoleId);
    }

    if (loadedFromFile || loadedFromPayload)
    {
        u32 oldActiveRoleId = g_vm_net_mock_role_db.activeRoleId;
        for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
        {
            u32 newRoleId = 0;
            migratedOldIds[migratedIdCount] = g_vm_net_mock_role_db.roles[i].roleId;
            if (!vm_net_mock_allocate_global_role_id(&newRoleId))
            {
                vm_autotest_note("mock_role_id_global_migrate_failed account=%s old=%u error=%s\n",
                                 g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                                 migratedOldIds[migratedIdCount], vm_mysql_last_error());
                g_vm_net_mock_role_db_valid = false;
                return;
            }
            migratedNewIds[migratedIdCount] = newRoleId;
            g_vm_net_mock_role_db.roles[i].roleId = newRoleId;
            if (oldActiveRoleId == migratedOldIds[migratedIdCount])
                g_vm_net_mock_role_db.activeRoleId = newRoleId;
            ++migratedIdCount;
        }
        needsSave = true;
    }

    bool activeFound = false;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (g_vm_net_mock_role_db.roles[i].roleId == g_vm_net_mock_role_db.activeRoleId)
        {
            activeFound = true;
            break;
        }
    }
    if (!activeFound && g_vm_net_mock_role_db.roleCount > 0)
    {
        g_vm_net_mock_role_db.activeRoleId = g_vm_net_mock_role_db.roles[0].roleId;
        needsSave = true;
    }
    else if (g_vm_net_mock_role_db.roleCount == 0 && g_vm_net_mock_role_db.activeRoleId != 0)
    {
        g_vm_net_mock_role_db.activeRoleId = 0;
        needsSave = true;
    }
    g_vm_net_mock_role_db_valid = true;
    if (needsSave)
    {
        const char *saveReason = loadedFromPayload ? "payload-relational-migrate" :
                                 loadedFromFile ? "legacy-relational-migrate" :
                                 loadedFromMysql ? "normalize" : "init";
        if (!vm_net_mock_role_db_save_relational(saveReason,
                                                 migratedOldIds,
                                                 migratedNewIds,
                                                 migratedIdCount))
        {
            g_vm_net_mock_role_db_valid = false;
            return;
        }
        if (migratedIdCount > 0)
        {
            vm_net_mock_apply_role_id_migration_to_friend_cache(
                g_vm_mock_service_active_account_id,
                migratedOldIds, migratedNewIds, migratedIdCount);
            for (u32 i = 0; i < migratedIdCount; ++i)
            {
                vm_autotest_note("mock_role_id_global_migrate account=%s old=%u new=%u\n",
                                 g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                                 migratedOldIds[i], migratedNewIds[i]);
            }
        }
    }
    vm_autotest_note("mock_role_db_mysql_load account=%s source=%s roles=%u active=%u\n",
                     g_vm_mock_service_active_account_id ? g_vm_mock_service_active_account_id : "-",
                     loadedFromMysql ? "relational" : loadedFromPayload ? "payload-migrate" :
                     loadedFromFile ? "legacy-migrate" : "init",
                     g_vm_net_mock_role_db.roleCount,
                     g_vm_net_mock_role_db.activeRoleId);
}

static vm_net_mock_role_state *vm_net_mock_active_role(void)
{
    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid || g_vm_net_mock_role_db.roleCount == 0)
        return NULL;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (g_vm_net_mock_role_db.roles[i].roleId == g_vm_net_mock_role_db.activeRoleId)
            return &g_vm_net_mock_role_db.roles[i];
    }
    g_vm_net_mock_role_db.activeRoleId = g_vm_net_mock_role_db.roles[0].roleId;
    return &g_vm_net_mock_role_db.roles[0];
}

static bool vm_net_mock_parse_u32_strict(const char *text, u32 *valueOut)
{
    char *end = NULL;
    unsigned long value = 0;

    if (valueOut)
        *valueOut = 0;
    if (text == NULL || text[0] == 0)
        return false;
    value = strtoul(text, &end, 10);
    if (end == NULL || *end != 0 || value > 0xfffffffful)
        return false;
    if (valueOut)
        *valueOut = (u32)value;
    return true;
}

static vm_net_mock_role_state *vm_net_mock_find_role_in_db(vm_net_mock_role_db_file *db,
                                                           const char *selector)
{
    u32 roleId = 0;

    if (db == NULL || db->roleCount == 0)
        return NULL;
    if (selector == NULL || selector[0] == 0 || strcmp(selector, "active") == 0)
    {
        for (u32 i = 0; i < db->roleCount; ++i)
        {
            if (db->roles[i].roleId == db->activeRoleId)
                return &db->roles[i];
        }
        return &db->roles[0];
    }
    if (vm_net_mock_parse_u32_strict(selector, &roleId))
    {
        for (u32 i = 0; i < db->roleCount; ++i)
        {
            if (db->roles[i].roleId == roleId)
                return &db->roles[i];
        }
    }
    for (u32 i = 0; i < db->roleCount; ++i)
    {
        if (strcmp(db->roles[i].name, selector) == 0)
            return &db->roles[i];
    }
    return NULL;
}

static u32 vm_net_mock_role_wcoin_balance(const vm_net_mock_role_state *role)
{
    return role ? role->wcoin : 0;
}

static u32 vm_net_mock_role_add_wcoin(vm_net_mock_role_state *role, u32 amount)
{
    uint64_t total = 0;

    if (role == NULL || amount == 0)
        return role ? role->wcoin : 0;
    total = (uint64_t)role->wcoin + (uint64_t)amount;
    role->wcoin = total > 0xffffffffull ? 0xffffffffu : (u32)total;
    return role->wcoin;
}

static bool vm_net_mock_select_active_role(u32 roleId)
{
    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid || roleId == 0)
        return false;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (g_vm_net_mock_role_db.roles[i].roleId == roleId)
        {
            if (g_vm_net_mock_role_db.activeRoleId != roleId)
            {
                g_vm_net_mock_role_db.activeRoleId = roleId;
                vm_net_mock_role_db_save("role-select");
            }
            return true;
        }
    }
    return false;
}

static bool vm_net_mock_role_db_has_role_id(u32 roleId)
{
    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid || roleId == 0)
        return false;
    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (g_vm_net_mock_role_db.roles[i].roleId == roleId)
            return true;
    }
    return false;
}

static u8 vm_net_mock_active_role_job_or(u8 fallback)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role == NULL || role->job == 0 || role->job > 3)
        return fallback;
    return role->job;
}

static u8 vm_net_mock_active_role_sex_or(u8 fallback)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role == NULL || role->sex > 1)
        return fallback;
    return role->sex;
}

static u8 vm_net_mock_role_db_sex_from_title_value(u8 rawSex)
{
    if (rawSex >= 1 && rawSex <= 2)
        return (u8)(rawSex - 1);
    if (rawSex == 0)
        return 0;
    return 0;
}

static u8 vm_net_mock_role_db_job_from_title_value(u8 rawJob, bool rawJobIsIndex)
{
    if (rawJobIsIndex)
    {
        if (rawJob <= 2)
            return (u8)(rawJob + 1);
        return 1;
    }
    if (rawJob >= 1 && rawJob <= 3)
        return rawJob;
    if (rawJob == 0)
        return 1;
    return 1;
}

static u32 vm_net_mock_role_db_next_role_id(void)
{
    u32 nextRoleId = 0;
    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid || !vm_net_mock_allocate_global_role_id(&nextRoleId))
        return 0;
    return nextRoleId;
}

static void vm_net_mock_copy_role_name(char *out, size_t outCap, const char *name)
{
    size_t copyLen = 0;
    if (out == NULL || outCap == 0)
        return;
    out[0] = 0;
    if (name != NULL)
    {
        copyLen = strlen(name);
        if (copyLen >= outCap)
            copyLen = outCap - 1;
        while (copyLen > 0 && name[copyLen - 1] == 0)
            --copyLen;
        if (copyLen > 0)
            memcpy(out, name, copyLen);
        out[copyLen] = 0;
    }
    if (out[0] == 0)
        snprintf(out, outCap, "%s", vm_net_mock_default_role_name());
}

static bool vm_net_mock_role_db_create_from_title(const vm_net_mock_title_role_create_request *request,
                                                  u32 *actorIdOut,
                                                  u8 *resultOut)
{
    vm_net_mock_role_state *role = NULL;
    u32 actorId = 0;
    u32 previousActiveRoleId = 0;
    u8 result = 1;

    if (actorIdOut)
        *actorIdOut = 0;
    if (resultOut)
        *resultOut = result;
    if (request == NULL)
        return false;

    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid ||
        g_vm_net_mock_role_db.roleCount >= VM_NET_MOCK_ROLE_DB_MAX_ROLES)
    {
        return true;
    }

    actorId = vm_net_mock_role_db_next_role_id();
    if (actorId == 0)
        return true;
    previousActiveRoleId = g_vm_net_mock_role_db.activeRoleId;
    role = &g_vm_net_mock_role_db.roles[g_vm_net_mock_role_db.roleCount];
    vm_net_mock_role_init_default(role);
    role->roleId = actorId;
    if (request->name[0] != 0)
        vm_net_mock_copy_role_name(role->name, sizeof(role->name), request->name);
    else
        vm_net_mock_role_assign_fallback_name(role);
    role->job = vm_net_mock_role_db_job_from_title_value(request->rawJob, request->rawJobIsIndex);
    role->sex = vm_net_mock_role_db_sex_from_title_value(request->rawSex);
    vm_net_mock_role_init_default_equipment(role);
    vm_net_mock_role_normalize(role);
    role->hp = role->hpMax;
    role->mp = role->mpMax;

    g_vm_net_mock_role_db.roleCount += 1;
    g_vm_net_mock_role_db.activeRoleId = actorId;
    if (!vm_net_mock_role_db_save_relational("role-create", NULL, NULL, 0))
    {
        --g_vm_net_mock_role_db.roleCount;
        memset(role, 0, sizeof(*role));
        g_vm_net_mock_role_db.activeRoleId = previousActiveRoleId;
        return true;
    }

    result = 0;
    if (actorIdOut)
        *actorIdOut = actorId;
    if (resultOut)
        *resultOut = result;
    return true;
}

static bool vm_net_mock_role_db_delete_by_id(u32 actorId, u8 *resultOut, u32 *roleCountOut)
{
    u8 result = 1;
    u32 deleteIndex = VM_NET_MOCK_ROLE_DB_MAX_ROLES;

    if (resultOut)
        *resultOut = result;
    if (roleCountOut)
        *roleCountOut = 0;
    if (actorId == 0)
        return false;

    vm_net_mock_role_db_load();
    if (!g_vm_net_mock_role_db_valid)
        return false;

    for (u32 i = 0; i < g_vm_net_mock_role_db.roleCount; ++i)
    {
        if (g_vm_net_mock_role_db.roles[i].roleId == actorId)
        {
            deleteIndex = i;
            break;
        }
    }

    if (deleteIndex == VM_NET_MOCK_ROLE_DB_MAX_ROLES)
    {
        if (roleCountOut)
            *roleCountOut = g_vm_net_mock_role_db.roleCount;
        return true;
    }

    for (u32 i = deleteIndex; i + 1 < g_vm_net_mock_role_db.roleCount; ++i)
        g_vm_net_mock_role_db.roles[i] = g_vm_net_mock_role_db.roles[i + 1];
    if (g_vm_net_mock_role_db.roleCount > 0)
    {
        memset(&g_vm_net_mock_role_db.roles[g_vm_net_mock_role_db.roleCount - 1],
               0,
               sizeof(g_vm_net_mock_role_db.roles[g_vm_net_mock_role_db.roleCount - 1]));
        g_vm_net_mock_role_db.roleCount -= 1;
    }

    if (g_vm_net_mock_role_db.roleCount == 0)
    {
        g_vm_net_mock_role_db.activeRoleId = 0;
    }
    else if (g_vm_net_mock_role_db.activeRoleId == actorId)
    {
        g_vm_net_mock_role_db.activeRoleId = g_vm_net_mock_role_db.roles[0].roleId;
    }

    vm_net_mock_role_db_save("role-delete");
    result = 0;
    if (resultOut)
        *resultOut = result;
    if (roleCountOut)
        *roleCountOut = g_vm_net_mock_role_db.roleCount;
    return true;
}

static void vm_net_mock_role_set_position(const char *scene, u16 x, u16 y, const char *reason)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role == NULL || scene == NULL || scene[0] == 0 || x == 0 || y == 0)
        return;
    snprintf(role->scene, sizeof(role->scene), "%s", scene);
    (void)vm_net_mock_role_canonicalize_initial_scene(role);
    role->x = x;
    role->y = y;
    vm_net_mock_role_normalize(role);
    vm_net_mock_role_db_save(reason ? reason : "position");
}

static void vm_net_mock_role_set_timeline_position(const char *scene,
                                                   u16 x,
                                                   u16 y,
                                                   const char *reason)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();

    if (role == NULL || !vm_net_mock_scene_name_is_safe(scene) || x == 0 || y == 0)
        return;
    /*
     * A movement timeline starts from the session's already validated scene
     * position and applies only the client's exact 4-pixel direction steps.
     * Re-running SCE landing/portal normalization here is both semantically
     * wrong (this is not a scene landing) and expensive on every upload.
     */
    snprintf(role->scene, sizeof(role->scene), "%s", scene);
    (void)vm_net_mock_role_canonicalize_initial_scene(role);
    role->x = x;
    role->y = y;
    g_vm_net_mock_role_position_dirty = true;
    (void)reason;
}

static bool vm_net_mock_role_add_backpack_item_to_role(vm_net_mock_role_state *role,
                                                        u32 itemId,
                                                        u32 count,
                                                        u16 *seqOut,
                                                        const char *reason)
{
    const vm_net_mock_item_effect_catalog_item *effect = NULL;
    u32 reservoirCapacity = 0;
    u8 itemCount = 0;

    if (seqOut)
        *seqOut = 0;
    if (role == NULL || itemId == 0 || count == 0)
        return false;

    vm_net_mock_role_normalize_backpack(role);
    itemCount = vm_net_mock_role_backpack_count(role);
    effect = vm_net_mock_find_item_effect_catalog_item(itemId);
    reservoirCapacity = vm_net_mock_item_effect_reservoir_capacity(effect);
    if (reservoirCapacity != 0)
    {
        u32 freeSlots = role->backpackCapacity > itemCount
                            ? (u32)role->backpackCapacity - itemCount
                            : 0;
        u16 firstSeq = 0;

        /*
         * item.dsh marks the two vitality flasks as stack=1/consumeMode=2.
         * JianghuOL.CBE:0x10336CA stores their remaining HP/MP pool in the
         * backpack row's u32 count field, so each acquired flask needs its own
         * sequence and starts with the DSH capacity rather than count=1.
         */
        if (count > freeSlots || count > VM_NET_MOCK_BACKPACK_MAX_ITEMS - itemCount)
            return false;
        for (u32 unit = 0; unit < count; ++unit)
        {
            vm_net_mock_backpack_item_state *item = &role->backpackItems[itemCount + unit];
            memset(item, 0, sizeof(*item));
            item->itemId = itemId;
            item->seq = role->nextBackpackSeq;
            if (item->seq == 0)
                item->seq = 1;
            item->count = reservoirCapacity;
            if (firstSeq == 0)
                firstSeq = item->seq;
            role->nextBackpackSeq = (u16)(item->seq + 1);
            if (role->nextBackpackSeq == 0)
                role->nextBackpackSeq = 1;
        }
        role->backpackItemCount = (u8)(itemCount + count);
        if (seqOut)
            *seqOut = firstSeq;
        vm_net_mock_role_normalize_backpack(role);
        vm_net_mock_role_db_save(reason ? reason : "backpack-add-reservoir-item");
        return true;
    }
    for (u32 i = 0; i < itemCount; ++i)
    {
        vm_net_mock_backpack_item_state *item = &role->backpackItems[i];
        if (item->itemId == itemId)
        {
            if (0xffffffffu - item->count < count)
                item->count = 0xffffffffu;
            else
                item->count += count;
            if (seqOut)
                *seqOut = item->seq;
            vm_net_mock_role_normalize_backpack(role);
            vm_net_mock_role_db_save(reason ? reason : "backpack-add-stack");
            return true;
        }
    }

    if (itemCount >= role->backpackCapacity || itemCount >= VM_NET_MOCK_BACKPACK_MAX_ITEMS)
        return false;

    vm_net_mock_backpack_item_state *item = &role->backpackItems[itemCount];
    memset(item, 0, sizeof(*item));
    item->itemId = itemId;
    item->seq = role->nextBackpackSeq;
    if (item->seq == 0)
        item->seq = 1;
    item->count = count;
    role->backpackItemCount = (u8)(itemCount + 1);
    role->nextBackpackSeq = (u16)(item->seq + 1);
    if (role->nextBackpackSeq == 0)
        role->nextBackpackSeq = 1;
    if (seqOut)
        *seqOut = item->seq;
    vm_net_mock_role_normalize_backpack(role);
    vm_net_mock_role_db_save(reason ? reason : "backpack-add-item");
    return true;
}

static bool vm_net_mock_role_add_backpack_item(u32 itemId, u32 count, u16 *seqOut)
{
    return vm_net_mock_role_add_backpack_item_to_role(
        vm_net_mock_active_role(), itemId, count, seqOut, NULL);
}

static vm_net_mock_backpack_item_state *vm_net_mock_role_find_backpack_item(vm_net_mock_role_state *role,
                                                                            u32 itemId,
                                                                            u16 seq)
{
    u8 itemCount = 0;

    if (role == NULL || (itemId == 0 && seq == 0))
        return NULL;

    vm_net_mock_role_normalize_backpack(role);
    itemCount = vm_net_mock_role_backpack_count(role);
    if (seq != 0)
    {
        for (u32 i = 0; i < itemCount; ++i)
        {
            vm_net_mock_backpack_item_state *item = &role->backpackItems[i];
            if (item->seq == seq && (itemId == 0 || item->itemId == itemId))
                return item;
        }
    }
    if (itemId != 0)
    {
        for (u32 i = 0; i < itemCount; ++i)
        {
            vm_net_mock_backpack_item_state *item = &role->backpackItems[i];
            if (item->itemId == itemId)
                return item;
        }
    }
    return NULL;
}

static vm_net_mock_backpack_item_state *vm_net_mock_role_find_backpack_item_by_effect(vm_net_mock_role_state *role,
                                                                                      u32 hp,
                                                                                      u32 mp,
                                                                                      u32 exp)
{
    u8 itemCount = 0;

    if (role == NULL || (hp == 0 && mp == 0 && exp == 0))
        return NULL;
    vm_net_mock_role_normalize_backpack(role);
    itemCount = vm_net_mock_role_backpack_count(role);
    for (u32 i = 0; i < itemCount; ++i)
    {
        vm_net_mock_backpack_item_state *item = &role->backpackItems[i];
        const vm_net_mock_item_effect_catalog_item *effect =
            vm_net_mock_find_item_effect_catalog_item(item->itemId);
        if (!vm_net_mock_item_effect_is_usable(effect))
            continue;
        if ((hp == 0 || effect->hp == hp) &&
            (mp == 0 || effect->mp == mp) &&
            (exp == 0 || effect->exp == exp))
        {
            return item;
        }
    }
    for (u32 i = 0; i < itemCount; ++i)
    {
        vm_net_mock_backpack_item_state *item = &role->backpackItems[i];
        const vm_net_mock_item_effect_catalog_item *effect =
            vm_net_mock_find_item_effect_catalog_item(item->itemId);
        if (vm_net_mock_item_effect_is_usable(effect))
            return item;
    }
    return NULL;
}

static bool vm_net_mock_role_consume_backpack_item(vm_net_mock_role_state *role,
                                                   u32 itemId,
                                                   u16 seq,
                                                   u32 count,
                                                   u32 *remainingOut)
{
    vm_net_mock_backpack_item_state *item = NULL;

    if (remainingOut)
        *remainingOut = 0;
    if (role == NULL || count == 0)
        return false;

    item = vm_net_mock_role_find_backpack_item(role, itemId, seq);
    if (item == NULL || item->count == 0)
        return false;

    if (item->count <= count)
    {
        item->count = 0;
        if (remainingOut)
            *remainingOut = 0;
    }
    else
    {
        item->count -= count;
        if (remainingOut)
            *remainingOut = item->count;
    }
    vm_net_mock_role_normalize_backpack(role);
    return true;
}

static bool vm_net_mock_role_equip_backpack_item(vm_net_mock_role_state *role,
                                                 u32 requestedItemId,
                                                 u16 requestedSeq,
                                                 u32 *equippedItemIdOut,
                                                 u16 *equippedSeqOut,
                                                 u8 *slotOut,
                                                 u32 *oldItemIdOut,
                                                 const char **reasonOut)
{
    vm_net_mock_backpack_item_state *item = NULL;
    const vm_net_mock_equipment_catalog_item *equip = NULL;
    u32 itemId = 0;
    u16 seq = 0;
    u32 oldItemId = 0;
    u8 slot = 0xff;
    u32 remaining = 0;
    bool selectedFreesSlot = false;

    if (equippedItemIdOut)
        *equippedItemIdOut = 0;
    if (equippedSeqOut)
        *equippedSeqOut = 0;
    if (slotOut)
        *slotOut = 0xff;
    if (oldItemIdOut)
        *oldItemIdOut = 0;
    if (reasonOut)
        *reasonOut = "ok";

    if (role == NULL)
    {
        if (reasonOut)
            *reasonOut = "no-role";
        return false;
    }

    item = vm_net_mock_role_find_backpack_item(role, requestedItemId, requestedSeq);
    if (item == NULL && requestedSeq != 0)
        item = vm_net_mock_role_find_backpack_item(role, 0, requestedSeq);
    if (item == NULL && requestedItemId != 0)
        item = vm_net_mock_role_find_backpack_item(role, requestedItemId, 0);
    if (item == NULL)
    {
        if (reasonOut)
            *reasonOut = "item-not-found";
        return false;
    }

    itemId = item->itemId;
    seq = item->seq;
    selectedFreesSlot = item->count <= 1;
    equip = vm_net_mock_find_equipment_catalog_item(itemId);
    if (equip == NULL || equip->slot >= VM_NET_MOCK_EQUIP_SLOT_COUNT)
    {
        if (reasonOut)
            *reasonOut = "not-equipment";
        return false;
    }
    if (role->level == 0)
        role->level = vm_net_mock_role_level_from_exp(role->exp);
    if (role->level < equip->levelRequired)
    {
        if (reasonOut)
            *reasonOut = "level-too-low";
        return false;
    }

    slot = equip->slot;
    oldItemId = role->equippedItemIds[slot];
    if (oldItemId != 0)
    {
        bool oldAlreadyStacked = vm_net_mock_role_find_backpack_item(role, oldItemId, 0) != NULL;
        u8 itemCount = vm_net_mock_role_backpack_count(role);
        if (!oldAlreadyStacked && !selectedFreesSlot && itemCount >= role->backpackCapacity)
        {
            if (reasonOut)
                *reasonOut = "bag-full-for-old";
            return false;
        }
    }

    if (!vm_net_mock_role_consume_backpack_item(role, itemId, seq, 1, &remaining))
    {
        if (reasonOut)
            *reasonOut = "consume-failed";
        return false;
    }
    role->equippedItemIds[slot] = itemId;
    if (oldItemId != 0)
    {
        u16 oldSeq = 0;
        if (!vm_net_mock_role_add_backpack_item(oldItemId, 1, &oldSeq))
        {
            role->equippedItemIds[slot] = oldItemId;
            (void)vm_net_mock_role_add_backpack_item(itemId, 1, NULL);
            if (reasonOut)
                *reasonOut = "old-return-failed";
            return false;
        }
    }

    vm_net_mock_role_sync_derived_vitals(role);
    vm_net_mock_role_db_save("item-equip");

    if (equippedItemIdOut)
        *equippedItemIdOut = itemId;
    if (equippedSeqOut)
        *equippedSeqOut = seq;
    if (slotOut)
        *slotOut = slot;
    if (oldItemIdOut)
        *oldItemIdOut = oldItemId;
    if (reasonOut)
        *reasonOut = "ok";
    (void)remaining;
    return true;
}

static bool vm_net_mock_role_unequip_item(vm_net_mock_role_state *role,
                                          u32 requestedItemId,
                                          u16 requestedSeq,
                                          u32 *unequippedItemIdOut,
                                          u16 *backpackSeqOut,
                                          u8 *slotOut,
                                          const char **reasonOut)
{
    u8 slot = 0xff;
    u32 itemId = 0;
    u16 seq = 0;
    const vm_net_mock_equipment_catalog_item *equip = NULL;

    if (unequippedItemIdOut)
        *unequippedItemIdOut = 0;
    if (backpackSeqOut)
        *backpackSeqOut = 0;
    if (slotOut)
        *slotOut = 0xff;
    if (reasonOut)
        *reasonOut = "ok";

    if (role == NULL)
    {
        if (reasonOut)
            *reasonOut = "no-role";
        return false;
    }

    if (requestedItemId != 0)
    {
        for (u8 i = 0; i < VM_NET_MOCK_EQUIP_SLOT_COUNT; ++i)
        {
            if (role->equippedItemIds[i] == requestedItemId)
            {
                slot = i;
                itemId = requestedItemId;
                break;
            }
        }
    }

    if (slot == 0xff && requestedItemId != 0)
    {
        equip = vm_net_mock_find_equipment_catalog_item(requestedItemId);
        if (equip != NULL && equip->slot < VM_NET_MOCK_EQUIP_SLOT_COUNT &&
            role->equippedItemIds[equip->slot] != 0)
        {
            slot = equip->slot;
            itemId = role->equippedItemIds[slot];
        }
    }

    if (slot == 0xff && requestedSeq != 0)
    {
        /*
         * The server state keeps equipped item ids, while the client request may
         * only carry the item seq assigned when it was equipped.  If there is a
         * single equipped item, the selector is still unambiguous.
         */
        u8 foundSlot = 0xff;
        for (u8 i = 0; i < VM_NET_MOCK_EQUIP_SLOT_COUNT; ++i)
        {
            if (role->equippedItemIds[i] == 0)
                continue;
            if (foundSlot != 0xff)
            {
                if (reasonOut)
                    *reasonOut = "ambiguous-seq";
                return false;
            }
            foundSlot = i;
        }
        if (foundSlot != 0xff)
        {
            slot = foundSlot;
            itemId = role->equippedItemIds[slot];
        }
    }

    if (slot == 0xff || itemId == 0)
    {
        if (reasonOut)
            *reasonOut = "equipped-item-not-found";
        return false;
    }

    if (!vm_net_mock_role_add_backpack_item(itemId, 1, &seq))
    {
        if (reasonOut)
            *reasonOut = "bag-full";
        return false;
    }

    role->equippedItemIds[slot] = 0;
    vm_net_mock_role_sync_derived_vitals(role);
    vm_net_mock_role_db_save("item-unequip");

    if (unequippedItemIdOut)
        *unequippedItemIdOut = itemId;
    if (backpackSeqOut)
        *backpackSeqOut = seq;
    if (slotOut)
        *slotOut = slot;
    if (reasonOut)
        *reasonOut = "ok";
    return true;
}

static u32 vm_net_mock_build_item_equip_response(const u8 *request, u32 requestLen,
                                                 u8 *out, u32 outCap)
{
    vm_net_mock_item_equip_request parsed;
    vm_net_mock_role_state *role = NULL;
    u32 itemId = 0;
    u16 seq = 0;
    u8 slot = 0xff;
    u32 oldItemId = 0;
    const char *reason = "not-matched";
    u8 result = 0;
    u32 pos = 5;
    u32 objectStart = 0;

    if (out == NULL || outCap < pos)
        return 0;
    if (!vm_net_mock_parse_item_equip_request(request, requestLen, &parsed))
        return 0;

    role = vm_net_mock_active_role();
    if (parsed.type == 3 && parsed.haveItemSelector &&
        vm_net_mock_role_equip_backpack_item(role, parsed.itemId, parsed.seq,
                                             &itemId, &seq, &slot, &oldItemId,
                                             &reason))
    {
        result = 1;
    }
    else if (parsed.type == 4 &&
             vm_net_mock_role_unequip_item(role, parsed.itemId, parsed.seq,
                                           &itemId, &seq, &slot, &reason))
    {
        result = 1;
    }
    else if (!parsed.haveItemSelector)
    {
        reason = "missing-selector";
    }

    /*
     * JianghuOL.CBE:0x01033544 subtype 8 reads type first.  For type=3,
     * result=1 moves the pending backpack item to the equipment manager. For
     * type=4, it moves the pending equipped item back into the backpack. Both
     * branches read the server-provided seq into item+276 before clearing wait.
     */
    if (!vm_net_mock_begin_wt_object(out, outCap, &pos, 1, 7, 8, &objectStart))
        return 0;
    if (!vm_net_mock_put_object_u8(out, outCap, &pos, "type", parsed.type))
        return 0;
    if (!vm_net_mock_put_object_u8(out, outCap, &pos, "result", result))
        return 0;
    if (!vm_net_mock_put_object_u16(out, outCap, &pos, "seq", seq ? seq : parsed.seq))
        return 0;
    vm_net_mock_finish_wt_object(out, objectStart, pos);
    vm_net_mock_finish_wt_packet(out, pos, 1);

    printf("[info][network] mock_item_equip type=%u requested_item=%u requested_seq=%u item=%u seq=%u slot=%u old=%u result=%u reason=%s resp=7/8 evidence=JianghuOL.CBE:0x01033544\n",
           parsed.type,
           parsed.itemId,
           parsed.seq,
           itemId,
           seq ? seq : parsed.seq,
           slot,
           oldItemId,
           result,
           reason ? reason : "-");
    vm_autotest_note("mock_item_equip type=%u requested_item=%u requested_seq=%u item=%u seq=%u slot=%u old=%u result=%u reason=%s response=7/8 evidence=JianghuOL.CBE:0x01033544(type3-result-seq)\n",
                     parsed.type,
                     parsed.itemId,
                     parsed.seq,
                     itemId,
                     seq ? seq : parsed.seq,
                     slot,
                     oldItemId,
                     result,
                     reason ? reason : "-");
    return pos;
}

static bool vm_net_mock_equipment_enhance_decode_materials(
    const vm_net_mock_equipment_enhance_request *parsed,
    u32 itemIds[5],
    u8 counts[5])
{
    u32 rowSize = 0;

    if (parsed == NULL || parsed->occultInfo == NULL ||
        parsed->materialRows == 0 || parsed->materialRows > 5)
    {
        return false;
    }
    rowSize = parsed->occultInfoLen / parsed->materialRows;
    if (rowSize != 9 && rowSize != 5)
        return false;
    for (u32 i = 0; i < parsed->materialRows; ++i)
    {
        const u8 *row = parsed->occultInfo + i * rowSize;
        u32 itemId = 0;
        u8 count = 0;

        if (rowSize == 9)
        {
            if (row[0] != 0 || row[1] != 4 ||
                row[6] != 0 || row[7] != 1)
            {
                return false;
            }
            itemId = ((u32)row[2] << 24) | ((u32)row[3] << 16) |
                     ((u32)row[4] << 8) | (u32)row[5];
            count = row[8];
        }
        else
        {
            itemId = ((u32)row[0] << 24) | ((u32)row[1] << 16) |
                     ((u32)row[2] << 8) | (u32)row[3];
            count = row[4];
        }
        if (itemId < VM_NET_MOCK_EQUIP_ENHANCE_CRYSTAL_FIRST ||
            itemId > VM_NET_MOCK_EQUIP_ENHANCE_CRYSTAL_LAST || count == 0)
        {
            return false;
        }
        itemIds[i] = itemId;
        counts[i] = count;
    }
    return true;
}

static bool vm_net_mock_equipment_enhance_validate_materials(
    vm_net_mock_role_state *role,
    const vm_net_mock_equipment_enhance_request *parsed,
    const u32 itemIds[5],
    const u8 counts[5],
    u32 *powerOut)
{
    u32 power = 0;

    if (powerOut)
        *powerOut = 0;
    if (role == NULL || parsed == NULL || parsed->materialRows == 0)
        return false;
    for (u32 i = 0; i < parsed->materialRows; ++i)
    {
        vm_net_mock_backpack_item_state *material = NULL;
        u32 requestedCount = 0;
        u32 tier = itemIds[i] - VM_NET_MOCK_EQUIP_ENHANCE_CRYSTAL_FIRST + 1;

        for (u32 j = 0; j < parsed->materialRows; ++j)
        {
            if (itemIds[j] == itemIds[i])
                requestedCount += counts[j];
        }
        material = vm_net_mock_role_find_backpack_item(role, itemIds[i], 0);
        if (material == NULL || material->count < requestedCount)
            return false;
        if (0xffffffffu - power < tier * 100u * counts[i])
            power = 0xffffffffu;
        else
            power += tier * 100u * counts[i];
    }
    if (powerOut)
        *powerOut = power;
    return true;
}

static u32 vm_net_mock_equipment_enhance_success_rate(u8 level, u32 power)
{
    u32 required = ((u32)level + 1u) * 100u;
    u32 rate = 0;

    if (required == 0)
        return 0;
    if (power >= required)
        return 100;
    rate = (power * 100u) / required;
    return rate > 100 ? 100 : rate;
}

static u32 vm_net_mock_equipment_enhance_money_cost(u8 level)
{
    return ((u32)level + 1u) * 100u;
}

static bool vm_net_mock_build_equipment_enhance_material_blob(
    u8 *out,
    u32 outCap,
    const vm_net_mock_equipment_enhance_request *parsed,
    const u32 itemIds[5],
    const u8 counts[5],
    u32 *blobLenOut)
{
    u32 pos = 0;

    if (blobLenOut)
        *blobLenOut = 0;
    if (out == NULL || parsed == NULL || blobLenOut == NULL)
        return false;
    for (u32 i = 0; i < parsed->materialRows; ++i)
    {
        if (!vm_net_mock_seq_put_u32(out, outCap, &pos, itemIds[i]) ||
            !vm_net_mock_seq_put_u8(out, outCap, &pos, counts[i]))
        {
            return false;
        }
    }
    *blobLenOut = pos;
    return true;
}

static u32 vm_net_mock_build_equipment_enhance_response(
    const u8 *request,
    u32 requestLen,
    u8 *out,
    u32 outCap)
{
    vm_net_mock_equipment_enhance_request parsed;
    vm_net_mock_role_state *role = NULL;
    vm_net_mock_backpack_item_state *equipment = NULL;
    const vm_net_mock_equipment_catalog_item *catalog = NULL;
    u32 itemIds[5];
    u8 counts[5];
    u8 data1[128];
    u8 data2[128];
    u8 occult[64];
    u32 data1Len = 0;
    u32 data2Len = 0;
    u32 occultLen = 0;
    u32 materialPower = 0;
    u32 successRate = 0;
    u32 moneyCost = 0;
    u32 equipmentItemId = 0;
    u32 pos = 5;
    u32 objectStart = 0;
    u8 result = 1;
    u8 currentLevel = 0;
    bool materialsValid = false;
    bool enhancementSucceeded = false;
    const char *reason = "ok";

    memset(&parsed, 0, sizeof(parsed));
    memset(itemIds, 0, sizeof(itemIds));
    memset(counts, 0, sizeof(counts));
    memset(data1, 0, sizeof(data1));
    memset(data2, 0, sizeof(data2));
    memset(occult, 0, sizeof(occult));
    if (out == NULL || outCap < pos ||
        !vm_net_mock_parse_equipment_enhance_request(request, requestLen,
                                                      &parsed))
    {
        return 0;
    }

    role = vm_net_mock_active_role();
    if (role != NULL)
        equipment = vm_net_mock_role_find_backpack_item(role, 0, parsed.equipSeq);
    if (equipment != NULL)
    {
        equipmentItemId = equipment->itemId;
        catalog = vm_net_mock_find_equipment_catalog_item(equipment->itemId);
    }
    if (equipment == NULL || catalog == NULL)
    {
        result = parsed.subtype == 1 ? 2 : 3;
        reason = "equipment-not-found";
    }
    else
    {
        currentLevel = (u8)SDL_min(
            equipment->enhanceLevel, VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL);
        if (currentLevel >= VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL)
        {
            result = parsed.subtype == 1 ? 3 : 5;
            reason = "max-level";
        }
    }

    if (parsed.subtype != 1 && result == 1)
    {
        materialsValid = vm_net_mock_equipment_enhance_decode_materials(
                             &parsed, itemIds, counts) &&
                         vm_net_mock_equipment_enhance_validate_materials(
                             role, &parsed, itemIds, counts, &materialPower);
        if (!materialsValid)
        {
            result = 4;
            reason = "crystal-insufficient";
        }
        else
        {
            successRate = vm_net_mock_equipment_enhance_success_rate(
                currentLevel, materialPower);
            moneyCost = vm_net_mock_equipment_enhance_money_cost(currentLevel);
        }
    }

    if (parsed.subtype == 3 && result == 1)
    {
        if (role->money < moneyCost)
        {
            result = 6;
            reason = "money-insufficient";
        }
        else
        {
            for (u32 i = 0; i < parsed.materialRows; ++i)
            {
                u32 remaining = 0;
                u32 consumeCount = counts[i];
                bool alreadyConsumed = false;

                for (u32 j = 0; j < i; ++j)
                {
                    if (itemIds[j] == itemIds[i])
                    {
                        alreadyConsumed = true;
                        break;
                    }
                }
                if (alreadyConsumed)
                    continue;
                for (u32 j = i + 1; j < parsed.materialRows; ++j)
                {
                    if (itemIds[j] == itemIds[i])
                        consumeCount += counts[j];
                }
                if (!vm_net_mock_role_consume_backpack_item(
                        role, itemIds[i], 0, consumeCount, &remaining))
                {
                    result = 4;
                    reason = "crystal-consume-failed";
                    break;
                }
            }
            if (result == 1)
            {
                u32 roll = (g_schedulerTick +
                            (u32)parsed.equipSeq * 17u +
                            (u32)currentLevel * 31u) % 100u;
                role->money -= moneyCost;
                enhancementSucceeded = roll < successRate;
                result = enhancementSucceeded ? 1 : 2;
                equipment = vm_net_mock_role_find_backpack_item(
                    role, 0, parsed.equipSeq);
                if (enhancementSucceeded && equipment != NULL)
                    equipment->enhanceLevel = (u16)(currentLevel + 1);
                vm_net_mock_role_db_save(enhancementSucceeded
                                             ? "equipment-enhance-success"
                                             : "equipment-enhance-failed");
                reason = enhancementSucceeded ? "success" : "failed-roll";
            }
        }
    }

    if (!vm_net_mock_begin_wt_object(out, outCap, &pos, 1, 29,
                                     parsed.subtype, &objectStart) ||
        !vm_net_mock_put_object_u8(out, outCap, &pos, "result", result))
    {
        return 0;
    }
    if (parsed.subtype == 1)
    {
        if (result == 1)
        {
            for (u32 level = 0;
                 level <= VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL; ++level)
            {
                if (!vm_net_mock_seq_put_u32(data1, sizeof(data1), &data1Len,
                                             (level + 1u) * 100u))
                    return 0;
            }
            for (u32 tier = 1;
                 tier <= VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL; ++tier)
            {
                if (!vm_net_mock_seq_put_u32(data2, sizeof(data2), &data2Len,
                                             tier * 100u))
                    return 0;
            }
        }
        if (!vm_net_mock_put_object_u16(out, outCap, &pos, "curlevel",
                                        currentLevel) ||
            !vm_net_mock_put_object_u16(
                out, outCap, &pos, "maxlevel",
                VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL) ||
            !vm_net_mock_put_object_u8(
                out, outCap, &pos, "num1",
                result == 1 ? VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL + 1 : 0) ||
            (result == 1 &&
             !vm_net_mock_put_object_raw(out, outCap, &pos, "data1", data1,
                                         (u16)data1Len)) ||
            !vm_net_mock_put_object_u8(
                out, outCap, &pos, "num2",
                result == 1 ? VM_NET_MOCK_EQUIP_ENHANCE_MAX_LEVEL : 0) ||
            (result == 1 &&
             !vm_net_mock_put_object_raw(out, outCap, &pos, "data2", data2,
                                         (u16)data2Len)))
        {
            return 0;
        }
    }
    else if (parsed.subtype == 2)
    {
        /* HandleItemUseAndEquip(0x01028C7C) reads both fields through the
         * response object's 32-bit numeric accessor (+68). */
        if (!vm_net_mock_put_object_u32(out, outCap, &pos, "value",
                                        successRate) ||
            !vm_net_mock_put_object_u32(out, outCap, &pos, "money",
                                        moneyCost))
        {
            return 0;
        }
    }
    else if ((result == 1 || result == 2) &&
             (!vm_net_mock_build_equipment_enhance_material_blob(
                  occult, sizeof(occult), &parsed, itemIds, counts,
                  &occultLen) ||
              !vm_net_mock_put_object_u8(out, outCap, &pos, "tnum",
                                         parsed.materialRows) ||
              !vm_net_mock_put_object_u16(out, outCap, &pos, "equipseq",
                                          parsed.equipSeq) ||
              !vm_net_mock_put_object_raw(out, outCap, &pos, "occult", occult,
                                          (u16)occultLen)))
    {
        return 0;
    }
    vm_net_mock_finish_wt_object(out, objectStart, pos);
    vm_net_mock_finish_wt_packet(out, pos, 1);

    printf("[info][network] mock_equipment_enhance phase=%u seq=%u item=%u level=%u result=%u crystals=%u power=%u rate=%u money=%u success=%u reason=%s resp=29/%u evidence=JianghuOL.CBE:0x0101CD1E+0x0101DD1E+0x01028C7C\n",
           parsed.subtype, parsed.equipSeq,
           equipmentItemId, currentLevel, result,
           parsed.materialRows, materialPower, successRate, moneyCost,
           enhancementSucceeded ? 1 : 0, reason, parsed.subtype);
    vm_autotest_note("mock_equipment_enhance phase=%u seq=%u item=%u level=%u result=%u crystals=%u power=%u rate=%u money=%u success=%u reason=%s response=29/%u evidence=JianghuOL.CBE:0x0101CD1E+0x0101DD1E+0x01028C7C\n",
                     parsed.subtype, parsed.equipSeq,
                     equipmentItemId, currentLevel, result,
                     parsed.materialRows, materialPower, successRate, moneyCost,
                     enhancementSucceeded ? 1 : 0, reason, parsed.subtype);
    return pos;
}

static u32 vm_net_mock_battle_reward_rand(void)
{
    if (g_vm_net_mock_battle_reward_rng == 0)
    {
        g_vm_net_mock_battle_reward_rng =
            0x6d2b79f5u ^
            (g_schedulerTick * 1664525u) ^
            (g_mockBattleOperateSessionSerial * 1013904223u) ^
            (g_vm_net_mock_role_db.activeRoleId << 1);
        if (g_vm_net_mock_battle_reward_rng == 0)
            g_vm_net_mock_battle_reward_rng = 0x9e3779b9u;
    }

    g_vm_net_mock_battle_reward_rng ^= g_vm_net_mock_battle_reward_rng << 13;
    g_vm_net_mock_battle_reward_rng ^= g_vm_net_mock_battle_reward_rng >> 17;
    g_vm_net_mock_battle_reward_rng ^= g_vm_net_mock_battle_reward_rng << 5;
    return g_vm_net_mock_battle_reward_rng;
}

static u8 vm_net_mock_battle_roll_enemy_count(bool useSceneMonsterStart)
{
    u32 minCount = 1;
    u32 maxCount = 3;
    const char *forcedSpec = getenv("CBE_BATTLE_ENEMY_COUNT");

    if (!useSceneMonsterStart)
        return 1;
    if (forcedSpec != NULL && forcedSpec[0] != 0)
    {
        u32 forced = vm_net_mock_env_u32("CBE_BATTLE_ENEMY_COUNT", 1);
        if (forced < 1)
            forced = 1;
        if (forced > 3)
            forced = 3;
        return (u8)forced;
    }

    minCount = vm_net_mock_env_u32("CBE_BATTLE_ENEMY_COUNT_MIN", minCount);
    maxCount = vm_net_mock_env_u32("CBE_BATTLE_ENEMY_COUNT_MAX", maxCount);
    if (minCount < 1)
        minCount = 1;
    if (maxCount < 1)
        maxCount = 1;
    if (minCount > 3)
        minCount = 3;
    if (maxCount > 3)
        maxCount = 3;
    if (minCount > maxCount)
    {
        u32 tmp = minCount;
        minCount = maxCount;
        maxCount = tmp;
    }
    return (u8)(minCount + (vm_net_mock_battle_reward_rand() % (maxCount - minCount + 1)));
}

static void vm_net_mock_battle_reset_enemy_hp_from_stats(u32 enemyId)
{
    vm_net_mock_monster_stats stats = vm_net_mock_monster_stats_for_enemy(enemyId);
    u8 enemyCount = vm_net_mock_battle_enemy_count_current();
    u32 perEnemyHp = vm_net_mock_env_u32("CBE_BATTLE_ENEMY_HP", stats.hp);
    u32 perEnemyMaxHp = vm_net_mock_env_u32("CBE_BATTLE_ENEMY_MAX_HP", perEnemyHp);

    if (perEnemyMaxHp < perEnemyHp)
        perEnemyMaxHp = perEnemyHp;
    for (u8 i = 0; i < 3; ++i)
    {
        if (i < enemyCount)
        {
            g_mockBattleEnemyHpSlots[i] = perEnemyHp;
            g_mockBattleEnemyHpMaxSlots[i] = perEnemyMaxHp;
        }
        else
        {
            g_mockBattleEnemyHpSlots[i] = 0;
            g_mockBattleEnemyHpMaxSlots[i] = 0;
        }
    }
    vm_net_mock_battle_sync_enemy_hp_totals();
}

static bool vm_net_mock_battle_roll_percent(u32 percent)
{
    if (percent == 0)
        return false;
    if (percent >= 100)
        return true;
    return (vm_net_mock_battle_reward_rand() % 100u) < percent;
}

static u32 vm_net_mock_battle_reward_exp_for_enemy(u32 enemyId)
{
    vm_net_mock_monster_stats stats = vm_net_mock_monster_stats_for_enemy(enemyId);
    return stats.exp;
}

static u32 vm_net_mock_battle_reward_gold_for_enemy(u32 enemyId)
{
    vm_net_mock_monster_stats stats = vm_net_mock_monster_stats_for_enemy(enemyId);
    return stats.gold;
}

static u32 vm_net_mock_battle_grant_reward_once(u32 *dropItemIdOut,
                                                u16 *dropSeqOut,
                                                u32 *dropCountOut,
                                                bool *dropGrantedOut)
{
    u32 rewardExp = 0;
    u32 dropItemId = 0;
    u16 dropSeq = 0;
    u32 dropCount = 0;
    bool dropGranted = false;
    vm_net_mock_monster_stats stats = vm_net_mock_monster_stats_for_enemy(g_vm_net_mock_battle_enemy_id_current);
    u32 enemyCount = vm_net_mock_battle_enemy_count_current();
    u32 dropRate = stats.dropRatePercent;
    u32 dropItemIdDefault = stats.dropItemId;

    if (dropItemIdOut)
        *dropItemIdOut = 0;
    if (dropSeqOut)
        *dropSeqOut = 0;
    if (dropCountOut)
        *dropCountOut = 0;
    if (dropGrantedOut)
        *dropGrantedOut = false;

    if (g_mockBattleOperateSessionSerial == 0)
        return 0;

    if (g_vm_net_mock_battle_rewarded_serial == g_mockBattleOperateSessionSerial)
    {
        if (dropItemIdOut)
            *dropItemIdOut = g_vm_net_mock_battle_rewarded_drop_item;
        if (dropSeqOut)
            *dropSeqOut = g_vm_net_mock_battle_rewarded_drop_seq;
        if (dropCountOut)
            *dropCountOut = g_vm_net_mock_battle_rewarded_drop_count;
        if (dropGrantedOut)
            *dropGrantedOut = g_vm_net_mock_battle_rewarded_drop_item != 0;
        return 0;
    }

    rewardExp = vm_net_mock_mul_capped_u32(
        vm_net_mock_env_u32_if_set("CBE_BATTLE_REWARD_EXP",
                                   vm_net_mock_battle_reward_exp_for_enemy(g_vm_net_mock_battle_enemy_id_current)),
        enemyCount);
    if (g_vm_net_mock_battle_enemy_id_current == VM_NET_MOCK_BATTLE_POISON_SLIME_ID)
    {
        dropRate = vm_net_mock_env_u32_if_set("CBE_BATTLE_CHANGMING_SAN_DROP_RATE", dropRate);
        dropItemIdDefault = vm_net_mock_env_u32_if_set("CBE_BATTLE_CHANGMING_SAN_ITEM_ID",
                                                       dropItemIdDefault);
    }
    dropRate = vm_net_mock_env_u32_if_set("CBE_BATTLE_DROP_RATE", dropRate);
    dropItemIdDefault = vm_net_mock_env_u32_if_set("CBE_BATTLE_DROP_ITEM_ID", dropItemIdDefault);
    if (dropItemIdDefault != 0)
    {
        for (u32 i = 0; i < enemyCount; ++i)
        {
            if (vm_net_mock_battle_roll_percent(dropRate))
                ++dropCount;
        }
    }
    if (dropItemIdDefault != 0 && dropCount != 0)
    {
        dropItemId = dropItemIdDefault;
        dropGranted = vm_net_mock_role_add_backpack_item(dropItemId, dropCount, &dropSeq);
        if (!dropGranted)
        {
            dropItemId = 0;
            dropSeq = 0;
            dropCount = 0;
        }
    }

    g_vm_net_mock_battle_rewarded_serial = g_mockBattleOperateSessionSerial;
    g_vm_net_mock_battle_rewarded_exp = rewardExp;
    g_vm_net_mock_battle_rewarded_drop_item = dropItemId;
    g_vm_net_mock_battle_rewarded_drop_seq = dropSeq;
    g_vm_net_mock_battle_rewarded_drop_count = dropCount;
    vm_net_mock_task_progress_after_battle(g_vm_net_mock_battle_enemy_id_current,
                                           enemyCount,
                                           dropItemId,
                                           dropCount);

    if (dropItemIdOut)
        *dropItemIdOut = dropItemId;
    if (dropSeqOut)
        *dropSeqOut = dropSeq;
    if (dropCountOut)
        *dropCountOut = dropCount;
    if (dropGrantedOut)
        *dropGrantedOut = dropGranted;
    return rewardExp;
}

static void vm_net_mock_role_apply_battle_settlement(u32 hp, u32 mp,
                                                     u32 rewardExp, u32 rewardGold,
                                                     u32 *lastExpOut, u32 *curExpOut,
                                                     u32 *percentExpOut, u32 *levelOut,
                                                     u32 *goldOut, u32 *hpOut, u32 *mpOut)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();

    if (role == NULL)
        return;
    vm_net_mock_role_sync_derived_vitals(role);
    if (hp > role->hpMax)
        hp = role->hpMax;
    if (mp > role->mpMax)
        mp = role->mpMax;
    role->hp = hp;
    role->mp = mp;
    vm_net_mock_role_add_exp(role, rewardExp);
    role->money = (0xffffffffu - role->money < rewardGold) ? 0xffffffffu : role->money + rewardGold;
    vm_net_mock_role_service_apply_battle_wear(role);
    vm_net_mock_role_normalize(role);
    vm_net_mock_role_db_save("battle-settle");

    if (lastExpOut)
        *lastExpOut = vm_net_mock_role_last_level_exp(role->exp);
    if (curExpOut)
        *curExpOut = vm_net_mock_role_next_level_start_exp(role->exp);
    if (percentExpOut)
        *percentExpOut = vm_net_mock_role_exp_percent(role->exp);
    if (levelOut)
        *levelOut = role->level;
    if (goldOut)
        *goldOut = role->money;
    if (hpOut)
        *hpOut = role->hp;
    if (mpOut)
        *mpOut = role->mp;
}

static u32 vm_net_mock_battle_recover_mp_value(void)
{
    return vm_net_mock_env_u32_if_set("CBE_BATTLE_RECOVER_MP", 0);
}

static u32 vm_net_mock_battle_apply_mp_recovery_once(vm_net_mock_role_state *role,
                                                     u32 roleMp,
                                                     u32 recoverMp,
                                                     bool *appliedOut)
{
    u32 mpMax = VM_NET_MOCK_ROLE_DEFAULT_MP;

    if (appliedOut)
        *appliedOut = false;
    if (role == NULL || recoverMp == 0 || g_mockBattleOperateSessionSerial == 0)
        return roleMp;
    if (g_vm_net_mock_battle_recovered_serial == g_mockBattleOperateSessionSerial)
        return roleMp;

    vm_net_mock_role_sync_derived_vitals(role);
    mpMax = role->mpMax ? role->mpMax : VM_NET_MOCK_ROLE_DEFAULT_MP;
    roleMp = vm_net_mock_min_u32(vm_net_mock_add_capped_u32(roleMp, recoverMp), mpMax);
    g_mockBattleRoleMpMax = mpMax;
    g_mockBattleRoleMpCurrent = roleMp;
    g_vm_net_mock_battle_recovered_serial = g_mockBattleOperateSessionSerial;
    if (appliedOut)
        *appliedOut = true;
    return roleMp;
}

static u32 vm_net_mock_role_current_hp_for_battle(void)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    u32 hp = 0;
    u32 hpMax = 0;
    vm_net_mock_role_default_vitals(role, &hp, &hpMax, NULL, NULL);
    (void)hpMax;
    return hp;
}

static void vm_net_mock_battle_save_terminal_role_state(const char *reason)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    u32 roleHp = g_mockBattleRoleHpMax != 0 ? g_mockBattleRoleHpCurrent :
                 (role ? role->hp : VM_NET_MOCK_ROLE_DEFAULT_HP);
    u32 roleMp = role ? role->mp : VM_NET_MOCK_ROLE_DEFAULT_MP;
    u32 rewardExp = 0;
    u32 rewardGold = 0;
    u32 statusLastExp = 0;
    u32 statusCurExp = 0;
    u32 statusPercentExp = 0;
    u32 statusLevel = 0;
    u32 statusGold = 0;
    u32 dropItemId = 0;
    u16 dropSeq = 0;
    u32 dropCount = 0;
    bool dropGranted = false;
    bool victory = g_mockBattleEnemyHpCurrent == 0 && roleHp > 0;
    bool rewardAlreadyGranted = false;
    u32 recoverMp = vm_net_mock_battle_recover_mp_value();
    bool mpRecoveryApplied = false;

    if (role == NULL)
        return;
    if (victory)
    {
        rewardAlreadyGranted = (g_vm_net_mock_battle_rewarded_serial == g_mockBattleOperateSessionSerial);
        rewardExp = vm_net_mock_battle_grant_reward_once(&dropItemId,
                                                         &dropSeq,
                                                         &dropCount,
                                                         &dropGranted);
        if (!rewardAlreadyGranted)
            rewardGold = vm_net_mock_mul_capped_u32(
                vm_net_mock_env_u32_if_set("CBE_BATTLE_REWARD_GOLD",
                                           vm_net_mock_battle_reward_gold_for_enemy(g_vm_net_mock_battle_enemy_id_current)),
                vm_net_mock_battle_enemy_count_current());
    }
    roleMp = vm_net_mock_battle_apply_mp_recovery_once(role, roleMp, recoverMp,
                                                       &mpRecoveryApplied);
    vm_net_mock_role_apply_battle_settlement(roleHp, roleMp, rewardExp, rewardGold,
                                             &statusLastExp, &statusCurExp,
                                             &statusPercentExp, &statusLevel,
                                             &statusGold, &roleHp, &roleMp);
    vm_autotest_note("mock_battle_terminal_save reason=%s enemy=%u enemies=%u victory=%u apply_exp=%u gold=%u total_exp=%u level=%u hp=%u mp=%u recover_mp=%u recovered=%u drop=%u seq=%u count=%u\n",
                     reason ? reason : "terminal",
                     g_vm_net_mock_battle_enemy_id_current,
                     vm_net_mock_battle_enemy_count_current(),
                     victory ? 1 : 0,
                     rewardExp,
                     statusGold,
                     role->exp,
                     statusLevel,
                     roleHp,
                     roleMp,
                     recoverMp,
                     mpRecoveryApplied ? 1 : 0,
                     dropGranted ? dropItemId : 0,
                     dropSeq,
                     dropCount);
}

static void vm_net_mock_battle_save_current_role_state(const char *reason)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();

    if (role == NULL)
        return;
    vm_net_mock_role_sync_derived_vitals(role);
    if (g_mockBattleRoleHpMax != 0)
    {
        u32 hpMax = role->hpMax ? role->hpMax : g_mockBattleRoleHpMax;
        role->hp = vm_net_mock_min_u32(g_mockBattleRoleHpCurrent, hpMax);
    }
    if (g_mockBattleRoleMpMax != 0)
    {
        u32 mpMax = role->mpMax ? role->mpMax : g_mockBattleRoleMpMax;
        role->mp = vm_net_mock_min_u32(g_mockBattleRoleMpCurrent, mpMax);
    }
    vm_net_mock_role_db_save(reason ? reason : "battle-state");
}

static u32 vm_net_mock_role_revive_floor_after_death(const char *reason)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    u32 reviveHp = 1;

    if (role == NULL)
        return 0;
    vm_net_mock_role_sync_derived_vitals(role);
    if (role->hpMax == 0)
        role->hpMax = VM_NET_MOCK_ROLE_DEFAULT_HP;
    if (reviveHp > role->hpMax)
        reviveHp = role->hpMax;
    if (role->hp == 0)
    {
        role->hp = reviveHp;
        vm_net_mock_role_db_save(reason ? reason : "death-revive-floor");
    }
    g_mockBattleRoleHpCurrent = role->hp;
    g_mockBattleRoleHpMax = role->hpMax;
    return role->hp;
}

static u32 vm_net_mock_percent_ceil_u32(u32 value, u32 percent)
{
    uint64_t scaled = (uint64_t)value * (uint64_t)percent;

    if (value == 0 || percent == 0)
        return 0;
    scaled = (scaled + 99ull) / 100ull;
    if (scaled == 0)
        scaled = 1;
    if (scaled > value)
        scaled = value;
    return (u32)scaled;
}

static u32 vm_net_mock_role_apply_death_penalty(const char *reason,
                                                u32 *expPenaltyOut,
                                                u32 *moneyPenaltyOut,
                                                u32 *reviveMpOut,
                                                char *sceneOut,
                                                size_t sceneOutCap,
                                                u16 *xOut,
                                                u16 *yOut)
{
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    const char *respawnScene = vm_net_mock_role_initial_scene_name();
    u16 respawnX = VM_NET_MOCK_ROLE_INITIAL_X;
    u16 respawnY = VM_NET_MOCK_ROLE_INITIAL_Y;
    u32 levelStartExp = 0;
    u32 levelProgressExp = 0;
    u32 expPenalty = 0;
    u32 moneyPenalty = 0;
    u32 reviveHp = 0;
    u32 reviveMp = 0;

    if (expPenaltyOut)
        *expPenaltyOut = 0;
    if (moneyPenaltyOut)
        *moneyPenaltyOut = 0;
    if (reviveMpOut)
        *reviveMpOut = 0;
    if (sceneOut && sceneOutCap != 0)
        sceneOut[0] = 0;
    if (xOut)
        *xOut = 0;
    if (yOut)
        *yOut = 0;
    if (role == NULL)
        return 0;

    vm_net_mock_role_sync_derived_vitals(role);
    levelStartExp = vm_net_mock_role_last_level_exp(role->exp);
    if (role->exp > levelStartExp)
        levelProgressExp = role->exp - levelStartExp;
    expPenalty = vm_net_mock_percent_ceil_u32(levelProgressExp,
                                             VM_NET_MOCK_ROLE_DEATH_EXP_PENALTY_PERCENT);
    if (expPenalty > levelProgressExp)
        expPenalty = levelProgressExp;
    role->exp -= expPenalty;
    role->level = vm_net_mock_role_level_from_exp(role->exp);
    moneyPenalty = vm_net_mock_percent_ceil_u32(role->money,
                                               VM_NET_MOCK_ROLE_DEATH_MONEY_PENALTY_PERCENT);
    role->money -= moneyPenalty;

    vm_net_mock_role_sync_derived_vitals(role);
    reviveHp = vm_net_mock_percent_ceil_u32(role->hpMax,
                                           VM_NET_MOCK_ROLE_DEATH_REVIVE_HP_PERCENT);
    reviveMp = vm_net_mock_percent_ceil_u32(role->mpMax,
                                           VM_NET_MOCK_ROLE_DEATH_REVIVE_MP_PERCENT);
    if (reviveHp == 0 && role->hpMax != 0)
        reviveHp = 1;
    if (reviveMp == 0 && role->mpMax != 0)
        reviveMp = 1;
    role->hp = vm_net_mock_min_u32(reviveHp, role->hpMax);
    role->mp = vm_net_mock_min_u32(reviveMp, role->mpMax);

    if (!vm_net_mock_scene_name_is_safe(respawnScene))
        respawnScene = vm_net_mock_default_scene_name();
    (void)vm_net_mock_get_scene_reasonable_spawn_from_sce(respawnScene,
                                                          &respawnX,
                                                          &respawnY,
                                                          NULL);
    vm_net_mock_adjust_safe_player_pos_for_scene(respawnScene, &respawnX, &respawnY);
    snprintf(role->scene, sizeof(role->scene), "%s", respawnScene);
    role->x = respawnX;
    role->y = respawnY;
    vm_net_mock_role_normalize(role);
    vm_net_mock_role_db_save(reason ? reason : "battle-death");

    g_mockBattleRoleHpCurrent = role->hp;
    g_mockBattleRoleHpMax = role->hpMax;
    g_mockBattleRoleMpCurrent = role->mp;
    g_mockBattleRoleMpMax = role->mpMax;

    if (expPenaltyOut)
        *expPenaltyOut = expPenalty;
    if (moneyPenaltyOut)
        *moneyPenaltyOut = moneyPenalty;
    if (reviveMpOut)
        *reviveMpOut = role->mp;
    if (sceneOut && sceneOutCap != 0)
        snprintf(sceneOut, sceneOutCap, "%s", role->scene);
    if (xOut)
        *xOut = role->x;
    if (yOut)
        *yOut = role->y;
    return role->hp;
}

static void vm_net_mock_save_player_pos_state(const char *scene, u16 x, u16 y, const char *reason)
{
    char runtimeScene[64];
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (x == 0 || y == 0)
        return;

    if (!vm_net_mock_scene_name_is_safe(scene))
    {
        if (vm_net_mock_read_runtime_scene_name(runtimeScene, sizeof(runtimeScene)))
            scene = runtimeScene;
        else if (role != NULL && vm_net_mock_scene_name_is_safe(role->scene))
            scene = role->scene;
        else
            scene = vm_net_mock_default_scene_name();
    }
    vm_net_mock_adjust_safe_player_pos_for_scene(scene, &x, &y);
    vm_net_mock_role_set_position(scene, x, y, reason);
}

static void vm_net_mock_mark_pending_scene_pos_save(const char *scene, u16 x, u16 y, const char *reason)
{
    if (!vm_net_mock_scene_name_is_safe(scene) || x == 0 || y == 0)
        return;
    snprintf(g_vm_net_mock_pending_scene_save_scene, sizeof(g_vm_net_mock_pending_scene_save_scene),
             "%s", scene);
    snprintf(g_vm_net_mock_pending_scene_save_reason, sizeof(g_vm_net_mock_pending_scene_save_reason),
             "%s", reason ? reason : "pending-scene-load");
    g_vm_net_mock_pending_scene_save_x = x;
    g_vm_net_mock_pending_scene_save_y = y;
    g_vm_net_mock_pending_scene_save_valid = true;
}

static const char *vm_net_mock_current_scene_name(void)
{
    const char *overrideName = vm_net_mock_env_str("CBE_SCENE_KEY", "");
    static char runtimeScene[64];
    if (vm_net_mock_read_runtime_scene_name(runtimeScene, sizeof(runtimeScene)))
        return vm_net_mock_normalize_scene_name_for_enter(runtimeScene);
    if (overrideName != NULL && overrideName[0] != 0)
        return overrideName;
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role != NULL && vm_net_mock_scene_name_is_safe(role->scene))
        return vm_net_mock_normalize_scene_name_for_enter(role->scene);
    return vm_net_mock_default_scene_name();
}

static u16 vm_net_mock_scene_spawn_x(void)
{
    if (getenv("CBE_SCENE_POS_X") != NULL)
        return (u16)vm_net_mock_env_u32("CBE_SCENE_POS_X", VM_NET_MOCK_ROLE_INITIAL_X);
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role != NULL && role->x != 0)
        return role->x;
    return VM_NET_MOCK_ROLE_INITIAL_X;
}

static u16 vm_net_mock_scene_spawn_y(void)
{
    if (getenv("CBE_SCENE_POS_Y") != NULL)
        return (u16)vm_net_mock_env_u32("CBE_SCENE_POS_Y", VM_NET_MOCK_ROLE_INITIAL_Y);
    vm_net_mock_role_state *role = vm_net_mock_active_role();
    if (role != NULL && role->y != 0)
        return role->y;
    return VM_NET_MOCK_ROLE_INITIAL_Y;
}

static const char *vm_net_mock_default_scene_name(void)
{
    /*
     * Fresh roles start on the Penglai TongQueTai island. The actual landing
     * point is resolved from this scene's SCE edge-portal spawn and then moved
     * away from the trigger rectangle; VM_NET_MOCK_ROLE_INITIAL_X/Y are only a
     * last-resort fallback when the SCE cannot be read.
     */
    return "\x63\x30\x30\xc5\xee\xc0\xb3\xcf\xc9\xb5\xba\x5f\x30\x31\x2e\x73\x63\x65"; /* GBK: c00PenglaiXiandao_01.sce */
}

static const char *vm_net_mock_scene_key_name(void)
{
    const char *overrideName = vm_net_mock_env_str("CBE_SCENE_KEY", "");
    vm_net_mock_role_state *role = vm_net_mock_active_role();

    /*
     * This key is copied by parse_actorinfo_response() into R9+0x5E46 and later
     * reused as the mode-10 descriptor name by scene_rebuild_runtime_nodes().
     * The ASCII experiment proved the update path, but also bypassed the local
     * .sce scene descriptor and left the map background black when cached.
     * Keep the default aligned with 30/1.scene and use CBE_SCENE_KEY for
     * non-colliding descriptor experiments.
     */
    if (overrideName != NULL && overrideName[0] != 0)
        return overrideName;
    if (role != NULL && vm_net_mock_scene_name_is_safe(role->scene))
        return vm_net_mock_normalize_scene_name_for_enter(role->scene);
    return vm_net_mock_current_scene_name();
}

static const char *vm_net_mock_fb_target_info_text(void)
{
    const char *overrideInfo = vm_net_mock_env_str("CBE_FB_TARGET_INFO", "");
    if (overrideInfo != NULL && overrideInfo[0] != 0)
        return overrideInfo;
    return "";
}

static bool vm_net_mock_put_scene_fields_with(u8 *out, u32 outCap, u32 *pos,
                                               bool includeResult, bool includeType, u8 requestType,
                                               const char *sceneName, u16 spawnX, u16 spawnY)
{
    u8 posInfo[8];
    u32 posInfoLen = vm_net_mock_build_pos_info(posInfo, sizeof(posInfo), spawnX, spawnY);
    if (posInfoLen == 0)
        return false;
    if (includeResult && !vm_net_mock_put_object_u8(out, outCap, pos, "result", 1))
        return false;
    if (includeType && !vm_net_mock_put_object_u8(out, outCap, pos, "type", requestType))
        return false;
    if (!vm_net_mock_put_object_string(out, outCap, pos, "scene", sceneName ? sceneName : vm_net_mock_default_scene_name()))
        return false;
    return vm_net_mock_put_object_entry(out, outCap, pos, "posinfo", posInfo, (u16)posInfoLen);
}

static bool vm_net_mock_put_scene_ack_without_posinfo(u8 *out, u32 outCap, u32 *pos,
                                                      u8 requestType, const char *sceneName)
{
    if (!vm_net_mock_put_object_u8(out, outCap, pos, "result", 1))
        return false;
    if (!vm_net_mock_put_object_u8(out, outCap, pos, "type", requestType))
        return false;
    return vm_net_mock_put_object_string(out, outCap, pos, "scene",
                                         sceneName ? sceneName : vm_net_mock_default_scene_name());
}

static bool vm_net_mock_put_scene_fields(u8 *out, u32 outCap, u32 *pos, bool includeResult, bool includeType, u8 requestType)
{
    return vm_net_mock_put_scene_fields_with(out, outCap, pos,
                                             includeResult, includeType, requestType,
                                             vm_net_mock_scene_key_name(),
                                             vm_net_mock_scene_spawn_x(),
                                             vm_net_mock_scene_spawn_y());
}

