        return "local";
    case VM_MOCK_CHAT_TYPE_TEAM:
        return "team";
    case VM_MOCK_CHAT_TYPE_PRIVATE:
        return "private";
    case VM_MOCK_CHAT_TYPE_TEAM_NOTICE:
        return "team-notice";
